/**
 * Astro Bowl VR — Main Entry Point
 * Holodeck bowling game: dual-runtime (VR + browser), 10-pin scoring,
 * 5 ball types, 3 themes, procedural audio, achievements, leaderboard.
 */
import { World, Vector3, Color } from '@iwsdk/core';
import { GameManager, GameState } from './game';
import { BallController, BallState, BALL_TYPES } from './ball';
import { PinManager } from './pins';
import { LaneBuilder, LANE } from './lane';
import { EnvironmentBuilder, THEMES } from './environment';
import { EffectsManager } from './effects';
import { AudioManager } from './audio';
import { HUDManager } from './hud';
import { UIManager } from './ui';
import { XRInputHandler } from './xrinput';
import { BrowserInputHandler } from './browserinput';
import { AchievementTracker } from './achievements';
import { LeaderboardManager } from './leaderboard';
import { AimIndicator } from './aim';
import { ChallengeManager, ChallengeType } from './challenges';

// ── Bootstrap ──────────────────────────────────────────────────
const container = document.getElementById('scene-container')!;

const world = await World.create(container, {
  xr: { offer: 'once' },
  input: { canvasPointerEvents: true },
  render: {
    near: 0.01,
    far: 200,
    camera: {
      position: [0, 1.7, 1.5],
      lookAt: [0, 0.5, -10],
    },
  },
  features: {
    grabbing: false,
    locomotion: false,
    physics: false,
  },
});

// ── Systems Init ───────────────────────────────────────────────
const gameManager = new GameManager();
let currentTheme = 'neon_circuit';
const themeColors = THEMES[currentTheme];

const environment = new EnvironmentBuilder(currentTheme);
world.scene.add(environment.group);

const lane = new LaneBuilder(themeColors.primary, themeColors.secondary, themeColors.accent);
world.scene.add(lane.group);

const pinManager = new PinManager(themeColors.primary, themeColors.accent);
world.scene.add(pinManager.group);

let ball = new BallController('standard');
world.scene.add(ball.group);

const effects = new EffectsManager();
world.scene.add(effects.group);

const audio = new AudioManager();
const hud = new HUDManager();
const ui = new UIManager();
const achievements = new AchievementTracker();
const leaderboard = new LeaderboardManager();
const challengeManager = new ChallengeManager();

// Canvas for browser input
const canvas = container.querySelector('canvas') as HTMLCanvasElement;
const xrInput = new XRInputHandler(world);
const browserInput = canvas ? new BrowserInputHandler(world, canvas) : null;
const aimIndicator = new AimIndicator(themeColors.primary);
world.scene.add(aimIndicator.group);

// ── State Variables ────────────────────────────────────────────
let lastTime = performance.now() / 1000;
let ballThrown = false;
let waitingForSettle = false;
let scoreDisplayTimer = 0;
let frameTransitionTimer = 0;
let pinsKnockedThisRoll = 0;
let isXRSession = false;
let musicVolume = 0.3;
let sfxVolume = 0.6;
let gutterEventFired = false;
let challengeActive = false;

// ── Helper: apply theme ────────────────────────────────────────
function applyTheme(themeName: string) {
  const theme = THEMES[themeName];
  if (!theme) return;
  currentTheme = themeName;
  environment.applyTheme(themeName);
  // Lane and pins use fixed colors from initial creation;
  // for a theme change to fully propagate we'd rebuild them,
  // but the environment change gives the primary visual shift.
}

// ── Helper: reset for new frame/roll ───────────────────────────
function prepareForRoll() {
  ball.resetToReturn();
  ballThrown = false;
  waitingForSettle = false;
  pinsKnockedThisRoll = 0;
  gutterEventFired = false;
  hud.hidePowerBar();

  // Update HUD
  hud.updateScorecard(gameManager.frames, gameManager.currentFrame);
  hud.updateFrameIndicator(gameManager.currentFrame, gameManager.currentRoll, ball.ballType.name);
  hud.updatePinDisplay(gameManager.pinsStanding);
  hud.updateTotal(gameManager.totalScore);

  gameManager.setState(GameState.AIMING);
}

// ── Helper: throw the ball ─────────────────────────────────────
function throwBall(velocity: Vector3) {
  if (gameManager.state !== GameState.AIMING && gameManager.state !== GameState.THROWING) return;

  ball.throw(velocity);
  ballThrown = true;
  gameManager.setState(GameState.BALL_ROLLING);
  aimIndicator.hide();

  audio.init().then(() => {
    audio.startRollingSound();
    audio.playThrowWhoosh(velocity.length());
  });

  hud.hidePowerBar();
}

// ── Helper: handle roll result ─────────────────────────────────
function handleRollResult(pinsDown: number) {
  const result = gameManager.recordRoll(pinsDown);

  // Audio and effects
  audio.init().then(() => {
    if (result.isStrike) {
      audio.playStrikeFanfare();
      effects.playStrikeCelebration(new Vector3(0, 0.5, LANE.HEADPIN_Z));
      hud.showMessage('STRIKE!', '🎳', 2500);

      if (gameManager.stats.currentStreak >= 3) {
        audio.playTurkeyCelebration();
        effects.playTurkeyCelebration(new Vector3(0, 1, LANE.HEADPIN_Z));
        hud.showMessage('TURKEY!', `${gameManager.stats.currentStreak} strikes in a row!`, 3000);
      }

      achievements.recordStrike();
    } else if (result.isSpare) {
      audio.playSpareChime();
      effects.playSpareCelebration(new Vector3(0, 0.5, LANE.HEADPIN_Z));
      hud.showMessage('SPARE!', '/', 2000);
      achievements.recordSpare();
    } else if (pinsDown === 0) {
      audio.playGutterSad();
      hud.showMessage('GUTTER', '', 1500);
      achievements.recordGutter();
    } else {
      achievements.recordOpen();
    }

    if (pinsDown > 0) {
      audio.playPinScatter(pinsDown);
      effects.playPinHitEffect(new Vector3(0, 0.3, LANE.HEADPIN_Z), pinsDown / 10);
    }
  });

  // Update HUD
  hud.updateScorecard(gameManager.frames, gameManager.currentFrame);
  hud.updateTotal(gameManager.totalScore);

  if (result.gameOver) {
    // Game complete
    gameManager.setState(GameState.SCORE_DISPLAY);
    scoreDisplayTimer = 3;
  } else if (result.frameComplete) {
    // Frame complete, transition
    gameManager.setState(GameState.FRAME_TRANSITION);
    frameTransitionTimer = 1.5;
  } else {
    // Same frame, second roll — just clear fallen pins and re-aim
    gameManager.setState(GameState.FRAME_TRANSITION);
    frameTransitionTimer = 1.0;
  }
}

// ── Helper: end game ───────────────────────────────────────────
function endGame() {
  const score = gameManager.getTotalScore();
  const stats = gameManager.stats;

  // Save to leaderboard
  leaderboard.addScore({
    score,
    date: new Date().toLocaleDateString(),
    ballType: gameManager.ballType,
    theme: currentTheme,
    strikes: stats.strikes,
    spares: stats.spares,
  });

  // Check achievements
  achievements.recordGameComplete(score, stats);
  achievements.recordBallUsed(gameManager.ballType);
  achievements.recordThemePlayed(currentTheme);

  // Show game over screen
  hud.hide();
  audio.stopAmbientMusic();
  audio.stopRollingSound();
  ui.showGameOver(score, stats);
  gameManager.setState(GameState.GAME_OVER);
}

// ── Helper: start a new game ───────────────────────────────────
function startGame() {
  gameManager.reset();
  pinManager.resetPins();
  ball.resetToReturn();

  ui.hideAll();
  hud.show();

  audio.init().then(() => {
    audio.startAmbientMusic();
  });

  prepareForRoll();
}

// ── Wire up UI callbacks ───────────────────────────────────────
ui.onStartGame = () => startGame();
ui.onPlayAgain = () => startGame();
ui.onBallSelect = (ballType: string) => {
  gameManager.ballType = ballType;
  ball.setBallType(ballType);
};
ui.onThemeSelect = (theme: string) => {
  applyTheme(theme);
  gameManager.laneTheme = theme;
};
ui.onResume = () => {
  ui.hideAll();
  hud.show();
  gameManager.setState(gameManager.prevState);
};
ui.onQuit = () => {
  audio.stopAmbientMusic();
  audio.stopRollingSound();
  hud.hide();
  ui.showTitleScreen();
  gameManager.setState(GameState.TITLE);
};
ui.onShowLeaderboard = () => {
  const scores = leaderboard.getTopScores(10).map(e => ({ score: e.score, date: e.date }));
  ui.showLeaderboard(scores);
};
ui.onShowAchievements = () => {
  ui.showAchievements(achievements.getAll());
};

// ── Wire up challenges ─────────────────────────────────────────
ui.onStartChallenge = (type: ChallengeType) => {
  challengeManager.startChallenge(type);
  challengeActive = true;
  startGame(); // Reuse normal game start flow
};

challengeManager.onChallengeComplete = (success, stats) => {
  challengeActive = false;
  hud.hide();
  audio.stopAmbientMusic();
  audio.stopRollingSound();
  ui.showChallengeResult(success, challengeManager.currentChallenge?.name || '', stats);
  gameManager.setState(GameState.GAME_OVER);
};

// ── Wire up achievements ───────────────────────────────────────
achievements.onUnlock = (ach) => {
  hud.showMessage('🏆 UNLOCKED', ach.name, 3000);
  effects.playAchievementEffect();
  audio.init().then(() => audio.playAchievementUnlock());
};

// ── Wire up XR input ───────────────────────────────────────────
xrInput.onGrabBall = () => {
  if (gameManager.state === GameState.AIMING) {
    ball.state = BallState.HELD;
    gameManager.setState(GameState.THROWING);
    audio.init().then(() => audio.playUIClick());
  }
};

xrInput.onReleaseBall = (velocity: Vector3) => {
  if (gameManager.state === GameState.THROWING) {
    throwBall(velocity);
  }
};

xrInput.onConfirm = () => {
  const screen = ui.getActiveScreen();
  if (screen === 'ui-title-screen') {
    startGame();
  } else if (screen !== 'none') {
    // Generic confirm on active UI
  } else if (gameManager.state === GameState.AIMING) {
    // Quick throw — default forward
    throwBall(new Vector3(0, 0, -8));
  }
};

xrInput.onBack = () => {
  const screen = ui.getActiveScreen();
  if (screen !== 'none' && screen !== 'ui-title-screen') {
    ui.showTitleScreen();
  } else if (gameManager.state === GameState.PLAYING ||
             gameManager.state === GameState.AIMING) {
    hud.hide();
    ui.showPause();
    gameManager.setState(GameState.PAUSED);
  }
};

xrInput.onPause = () => {
  if (gameManager.state === GameState.PAUSED) {
    ui.hideAll();
    hud.show();
    gameManager.setState(gameManager.prevState);
  } else if (gameManager.state !== GameState.TITLE &&
             gameManager.state !== GameState.GAME_OVER &&
             gameManager.state !== GameState.LOADING) {
    hud.hide();
    ui.showPause();
    gameManager.setState(GameState.PAUSED);
  }
};

// ── Wire up Browser input ──────────────────────────────────────
if (browserInput) {
  browserInput.onStartCharge = () => {
    if (gameManager.state === GameState.AIMING) {
      gameManager.setState(GameState.THROWING);
      hud.showPowerBar();
      aimIndicator.show();
    }
  };

  browserInput.onPowerChange = (power: number) => {
    hud.setPower(power);
    aimIndicator.update(browserInput.getAimX(), power);
  };

  browserInput.onAimChange = (aimX: number) => {
    aimIndicator.update(aimX, browserInput.getPower());
  };

  browserInput.onThrow = (velocity: Vector3) => {
    if (gameManager.state === GameState.THROWING || gameManager.state === GameState.AIMING) {
      aimIndicator.hide();
      throwBall(velocity);
    }
  };

  browserInput.onConfirm = () => {
    const screen = ui.getActiveScreen();
    if (screen === 'ui-title-screen') {
      startGame();
    }
  };

  browserInput.onPause = () => {
    if (gameManager.state === GameState.PAUSED) {
      ui.hideAll();
      hud.show();
      gameManager.setState(gameManager.prevState);
    } else if (gameManager.state !== GameState.TITLE &&
               gameManager.state !== GameState.GAME_OVER &&
               gameManager.state !== GameState.LOADING) {
      hud.hide();
      ui.showPause();
      gameManager.setState(GameState.PAUSED);
    }
  };

  browserInput.onBack = () => {
    const screen = ui.getActiveScreen();
    if (screen !== 'none' && screen !== 'ui-title-screen') {
      ui.showTitleScreen();
    }
  };
}

// ── Wire up volume controls ────────────────────────────────────
(window as any).__onMusicVolChange = (v: number) => {
  musicVolume = v;
  audio.setMusicVolume(v);
};
(window as any).__onSfxVolChange = (v: number) => {
  sfxVolume = v;
  audio.setSFXVolume(v);
};

// ── Fog ────────────────────────────────────────────────────────
import { Fog } from '@iwsdk/core';
world.scene.fog = new Fog(themeColors.fog.getHex(), 15, 60);

// ── Show title screen ──────────────────────────────────────────
gameManager.setState(GameState.TITLE);
ui.showTitleScreen();

// ── Main game loop ─────────────────────────────────────────────
function gameLoop() {
  requestAnimationFrame(gameLoop);

  const now = performance.now() / 1000;
  let dt = Math.min(now - lastTime, 0.05); // Cap at 50ms
  lastTime = now;

  // Apply slow motion from effects
  dt *= effects.timeScale;

  const state = gameManager.state;

  // ── Update input handlers ──
  if (state !== GameState.LOADING && state !== GameState.TITLE) {
    xrInput.update(dt);
    if (browserInput) browserInput.update(dt);
  }

  // ── Ball follow controller in VR when held ──
  if (state === GameState.THROWING && ball.state === BallState.HELD) {
    const controllerPos = xrInput.getControllerPosition();
    if (controllerPos) {
      ball.position.copy(controllerPos);
      ball.mesh.position.copy(controllerPos);
    }
  }

  // ── Ball rolling physics ──
  if (state === GameState.BALL_ROLLING) {
    const ballResult = ball.update(dt);

    // Update rolling sound based on speed
    const speed = Math.sqrt(ball.velocity.x ** 2 + ball.velocity.z ** 2);
    audio.updateRollingSound(speed);

    // Gutter event (detect transition into gutter)
    if (ballResult.inGutter && !gutterEventFired) {
      gutterEventFired = true;
      audio.init().then(() => {
        audio.playGutterThud();
      });
      effects.playGutterEffect(ball.position.clone());
    }

    // Ball reached pin area — apply collision
    if (ballResult.reachedPins && !waitingForSettle) {
      pinsKnockedThisRoll = pinManager.applyBallImpact(
        ball.position,
        ball.velocity,
        ball.getRadius(),
        ball.ballType.mass,
      );
      waitingForSettle = true;

      if (ball.inGutter) {
        // Gutter ball = 0 pins
        pinsKnockedThisRoll = 0;
      }

      // Slow motion for strikes
      if (pinsKnockedThisRoll >= 8) {
        effects.startSlowMotion(1.0, 0.3);
      }
    }

    // Ball done rolling — wait for pins to settle
    if (ballResult.done || (waitingForSettle && ball.position.z < LANE.HEADPIN_Z - 1)) {
      audio.stopRollingSound();
      audio.init().then(() => audio.playBallReturn());

      if (!waitingForSettle) {
        // Ball stopped before reaching pins (gutter or slow ball)
        pinsKnockedThisRoll = 0;
        waitingForSettle = true;
      }

      gameManager.setState(GameState.PIN_SETTLING);
    }
  }

  // ── Pin settling ──
  if (state === GameState.PIN_SETTLING) {
    pinManager.updatePhysics(dt);
    if (pinManager.allSettled) {
      // Count actual pins down
      const standing = pinManager.countStanding();
      const totalPinsAtStart = gameManager.currentRoll === 0 ? 10 : gameManager.getPinsStanding();
      const actualKnocked = totalPinsAtStart - standing;
      const finalPinsDown = Math.max(0, actualKnocked);

      // Update game state pinsStanding
      for (let i = 0; i < 10; i++) {
        if (pinManager.pins[i]) {
          gameManager.pinsStanding[i] = pinManager.pins[i].standing;
        }
      }

      hud.updatePinDisplay(gameManager.pinsStanding);
      handleRollResult(finalPinsDown);
    }
  }

  // ── Score display timer ──
  if (state === GameState.SCORE_DISPLAY) {
    scoreDisplayTimer -= dt;
    if (scoreDisplayTimer <= 0) {
      endGame();
    }
  }

  // ── Frame transition ──
  if (state === GameState.FRAME_TRANSITION) {
    frameTransitionTimer -= dt;
    if (frameTransitionTimer <= 0) {
      // Determine if we need full pin reset or just second ball
      const needsReset = gameManager.needsPinReset();
      if (needsReset) {
        pinManager.startSweep(true, () => {
          audio.init().then(() => audio.playSweepSound());
          prepareForRoll();
        });
      } else {
        // Second ball — keep remaining pins
        prepareForRoll();
      }
      // Move to aiming state immediately (prepareForRoll sets it)
      // but if sweep is running, we wait in FRAME_TRANSITION
      if (!needsReset) {
        // Already handled by prepareForRoll
      } else {
        // Sweep is async — set a temp state
        gameManager.setState(GameState.FRAME_TRANSITION);
      }
    }
  }

  // ── Update visual systems ──
  const time = now;
  environment.update(time);
  lane.update(time);
  effects.update(dt);

  // Pin physics always need updating for falling animation
  if (state !== GameState.PIN_SETTLING) {
    pinManager.updatePhysics(dt);
  }
}

// Start the loop
gameLoop();

/**
 * Astro Bowl VR — XR Controller Input
 * Grip to grab ball, trigger release to throw (velocity from controller tracking),
 * thumbstick navigation, A/B buttons for menus.
 */
import { World, Vector3, Quaternion } from '@iwsdk/core';

// InputComponent enum values (matching @iwsdk/core)
const InputComponent = {
  Trigger: 0,
  Squeeze: 1,
  Thumbstick: 2,
  A_Button: 3,
  B_Button: 4,
} as const;

interface ControllerTrackingFrame {
  position: Vector3;
  time: number;
}

export class XRInputHandler {
  private world: World;
  private isGrabbingBall: boolean = false;
  private controllerHistory: ControllerTrackingFrame[] = [];
  private maxHistoryFrames: number = 10;
  private thumbstickCooldown: number = 0;
  private thumbstickDeadzone: number = 0.3;
  private sensitivity: number = 1.0;

  // Callbacks
  onGrabBall: () => void = () => {};
  onReleaseBall: (velocity: Vector3) => void = () => {};
  onMenuUp: () => void = () => {};
  onMenuDown: () => void = () => {};
  onMenuLeft: () => void = () => {};
  onMenuRight: () => void = () => {};
  onConfirm: () => void = () => {};
  onBack: () => void = () => {};
  onPause: () => void = () => {};

  constructor(world: World) {
    this.world = world;
  }

  setSensitivity(val: number) {
    this.sensitivity = val;
  }

  update(dt: number) {
    const xrInput = this.world.input?.xr;
    if (!xrInput) return;

    const rightGamepad = xrInput.gamepads?.right;
    const leftGamepad = xrInput.gamepads?.left;
    if (!rightGamepad) return;

    // Track controller position for velocity calculation
    const gripSpace = this.world.playerSpaceEntities?.gripSpaces?.right;
    if (gripSpace) {
      const pos = new Vector3();
      gripSpace.object3D.getWorldPosition(pos);
      this.controllerHistory.push({ position: pos, time: performance.now() / 1000 });
      if (this.controllerHistory.length > this.maxHistoryFrames) {
        this.controllerHistory.shift();
      }
    }

    // --- Squeeze (Grip) to grab ball ---
    const squeezePressed = rightGamepad.getButtonPressed?.(InputComponent.Squeeze)
      ?? rightGamepad.getButtonPressed?.(1);

    const squeezeDown = rightGamepad.getButtonDown?.(InputComponent.Squeeze)
      ?? rightGamepad.getButtonDown?.(1);

    const squeezeUp = rightGamepad.getButtonUp?.(InputComponent.Squeeze)
      ?? rightGamepad.getButtonUp?.(1);

    if (squeezeDown && !this.isGrabbingBall) {
      this.isGrabbingBall = true;
      this.controllerHistory = [];
      this.onGrabBall();
    }

    // --- Trigger to release/throw ball ---
    const triggerUp = rightGamepad.getButtonUp?.(InputComponent.Trigger)
      ?? rightGamepad.getButtonUp?.(0);

    const triggerDown = rightGamepad.getButtonDown?.(InputComponent.Trigger)
      ?? rightGamepad.getButtonDown?.(0);

    if (triggerUp && this.isGrabbingBall) {
      this.isGrabbingBall = false;
      const velocity = this.calculateThrowVelocity();
      this.onReleaseBall(velocity);
    }

    // Also release on grip release
    if (squeezeUp && this.isGrabbingBall) {
      this.isGrabbingBall = false;
      const velocity = this.calculateThrowVelocity();
      this.onReleaseBall(velocity);
    }

    // --- A Button: Confirm ---
    const aDown = rightGamepad.getButtonDown?.(InputComponent.A_Button)
      ?? rightGamepad.getButtonDown?.(3);
    if (aDown) {
      this.onConfirm();
    }

    // --- B Button: Back/Pause ---
    const bDown = rightGamepad.getButtonDown?.(InputComponent.B_Button)
      ?? rightGamepad.getButtonDown?.(4);
    if (bDown) {
      this.onBack();
    }

    // Left controller B button for pause
    if (leftGamepad) {
      const lbDown = leftGamepad.getButtonDown?.(InputComponent.B_Button)
        ?? leftGamepad.getButtonDown?.(4);
      if (lbDown) {
        this.onPause();
      }
    }

    // --- Thumbstick: Menu navigation ---
    this.thumbstickCooldown -= dt;
    if (this.thumbstickCooldown <= 0) {
      let axes: { x: number; y: number } | null = null;
      try {
        axes = rightGamepad.getAxesValues?.(InputComponent.Thumbstick);
      } catch {
        // Fallback: try to access raw axes
      }

      // Also try left thumbstick for navigation
      if (!axes && leftGamepad) {
        try {
          axes = leftGamepad.getAxesValues?.(InputComponent.Thumbstick);
        } catch {}
      }

      if (axes) {
        if (Math.abs(axes.y) > this.thumbstickDeadzone) {
          if (axes.y < -this.thumbstickDeadzone) {
            this.onMenuUp();
          } else if (axes.y > this.thumbstickDeadzone) {
            this.onMenuDown();
          }
          this.thumbstickCooldown = 0.25;
        }
        if (Math.abs(axes.x) > this.thumbstickDeadzone) {
          if (axes.x < -this.thumbstickDeadzone) {
            this.onMenuLeft();
          } else if (axes.x > this.thumbstickDeadzone) {
            this.onMenuRight();
          }
          this.thumbstickCooldown = 0.25;
        }
      }
    }
  }

  /**
   * Calculate throw velocity from controller tracking history.
   */
  private calculateThrowVelocity(): Vector3 {
    if (this.controllerHistory.length < 2) {
      return new Vector3(0, 0, -6); // Default forward throw
    }

    // Use the last few frames to calculate velocity
    const recent = this.controllerHistory.slice(-5);
    const first = recent[0];
    const last = recent[recent.length - 1];
    const timeDelta = last.time - first.time;

    if (timeDelta < 0.001) {
      return new Vector3(0, 0, -6);
    }

    const velocity = new Vector3(
      (last.position.x - first.position.x) / timeDelta,
      (last.position.y - first.position.y) / timeDelta,
      (last.position.z - first.position.z) / timeDelta,
    );

    // Scale velocity for game feel
    velocity.multiplyScalar(3.0 * this.sensitivity);

    // Clamp to reasonable range
    const speed = velocity.length();
    if (speed > 15) velocity.multiplyScalar(15 / speed);
    if (speed < 2) velocity.multiplyScalar(2 / speed);

    // Ensure ball goes forward (negative Z)
    if (velocity.z > -1) velocity.z = -Math.max(3, Math.abs(velocity.z));

    // Remove upward component (ball should stay on lane)
    velocity.y = 0;

    return velocity;
  }

  getControllerPosition(): Vector3 | null {
    const gripSpace = this.world.playerSpaceEntities?.gripSpaces?.right;
    if (!gripSpace) return null;
    const pos = new Vector3();
    gripSpace.object3D.getWorldPosition(pos);
    return pos;
  }

  isGrabbing(): boolean {
    return this.isGrabbingBall;
  }
}

/**
 * Astro Bowl VR — Game State Manager
 * Handles bowling scoring, frames, turn state, and game flow.
 */

export enum GameState {
  LOADING = 'loading',
  TITLE = 'title',
  BALL_SELECT = 'ball_select',
  SETTINGS = 'settings',
  PLAYING = 'playing',
  AIMING = 'aiming',
  THROWING = 'throwing',
  BALL_ROLLING = 'ball_rolling',
  PIN_SETTLING = 'pin_settling',
  SCORE_DISPLAY = 'score_display',
  FRAME_TRANSITION = 'frame_transition',
  GAME_OVER = 'game_over',
  LEADERBOARD = 'leaderboard',
  PAUSED = 'paused',
  CHALLENGE = 'challenge',
  PRACTICE = 'practice',
  ACHIEVEMENTS = 'achievements',
}

export interface FrameScore {
  rolls: number[];
  score: number | null; // null = not yet computable
  isStrike: boolean;
  isSpare: boolean;
  display: string;
}

export interface GameStats {
  strikes: number;
  spares: number;
  gutters: number;
  totalPins: number;
  maxStreak: number;
  currentStreak: number;
  perfectGame: boolean;
}

export class GameManager {
  state: GameState = GameState.LOADING;
  prevState: GameState = GameState.LOADING;
  frames: FrameScore[] = [];
  currentFrame: number = 0;
  currentRoll: number = 0; // 0 = first ball, 1 = second ball, 2 = bonus (10th frame)
  pinsStanding: boolean[] = new Array(10).fill(true);
  totalScore: number = 0;
  stats: GameStats = this.freshStats();
  ballType: string = 'standard';
  laneTheme: string = 'neon_circuit';
  gameComplete: boolean = false;
  private listeners: Map<string, Function[]> = new Map();

  constructor() {
    this.reset();
  }

  private freshStats(): GameStats {
    return {
      strikes: 0,
      spares: 0,
      gutters: 0,
      totalPins: 0,
      maxStreak: 0,
      currentStreak: 0,
      perfectGame: true,
    };
  }

  reset() {
    this.frames = [];
    for (let i = 0; i < 10; i++) {
      this.frames.push({
        rolls: [],
        score: null,
        isStrike: false,
        isSpare: false,
        display: '',
      });
    }
    this.currentFrame = 0;
    this.currentRoll = 0;
    this.pinsStanding = new Array(10).fill(true);
    this.totalScore = 0;
    this.stats = this.freshStats();
    this.gameComplete = false;
  }

  on(event: string, cb: Function) {
    if (!this.listeners.has(event)) this.listeners.set(event, []);
    this.listeners.get(event)!.push(cb);
  }

  emit(event: string, data?: any) {
    const cbs = this.listeners.get(event);
    if (cbs) cbs.forEach(cb => cb(data));
  }

  setState(newState: GameState) {
    this.prevState = this.state;
    this.state = newState;
    this.emit('stateChange', { from: this.prevState, to: newState });
  }

  /**
   * Record pins knocked down this roll.
   * Returns { pinsDown, isStrike, isSpare, frameComplete, gameOver }
   */
  recordRoll(pinsKnockedDown: number): {
    pinsDown: number;
    isStrike: boolean;
    isSpare: boolean;
    frameComplete: boolean;
    gameOver: boolean;
  } {
    const frame = this.frames[this.currentFrame];
    frame.rolls.push(pinsKnockedDown);

    this.stats.totalPins += pinsKnockedDown;
    if (pinsKnockedDown === 0) this.stats.gutters++;

    let isStrike = false;
    let isSpare = false;
    let frameComplete = false;
    let gameOver = false;

    if (this.currentFrame < 9) {
      // Frames 1-9
      if (this.currentRoll === 0) {
        if (pinsKnockedDown === 10) {
          // Strike
          isStrike = true;
          frame.isStrike = true;
          frame.display = 'X';
          frameComplete = true;
          this.stats.strikes++;
          this.stats.currentStreak++;
          this.stats.maxStreak = Math.max(this.stats.maxStreak, this.stats.currentStreak);
        } else {
          this.currentRoll = 1;
          // Update pins standing
          this.markPinsDown(pinsKnockedDown);
        }
      } else {
        // Second roll
        const firstRoll = frame.rolls[0];
        if (firstRoll + pinsKnockedDown === 10) {
          isSpare = true;
          frame.isSpare = true;
          frame.display = `${firstRoll}/`;
          this.stats.spares++;
        } else {
          frame.display = `${firstRoll}${pinsKnockedDown === 0 ? '-' : pinsKnockedDown}`;
          this.stats.currentStreak = 0;
          if (firstRoll + pinsKnockedDown < 10) this.stats.perfectGame = false;
        }
        frameComplete = true;
      }
    } else {
      // 10th frame — up to 3 rolls
      const rolls = frame.rolls;
      if (rolls.length === 1) {
        if (pinsKnockedDown === 10) {
          isStrike = true;
          frame.isStrike = true;
          this.stats.strikes++;
          this.stats.currentStreak++;
          this.stats.maxStreak = Math.max(this.stats.maxStreak, this.stats.currentStreak);
          this.currentRoll = 1;
          // Reset pins for next roll
          this.pinsStanding = new Array(10).fill(true);
        } else {
          this.currentRoll = 1;
          this.markPinsDown(pinsKnockedDown);
        }
      } else if (rolls.length === 2) {
        const first = rolls[0];
        const second = rolls[1];
        if (first === 10) {
          // After first strike
          if (pinsKnockedDown === 10) {
            isStrike = true;
            this.stats.strikes++;
            this.stats.currentStreak++;
            this.stats.maxStreak = Math.max(this.stats.maxStreak, this.stats.currentStreak);
            this.currentRoll = 2;
            this.pinsStanding = new Array(10).fill(true);
          } else if (first === 10 && second + pinsKnockedDown === 10 && second !== 10) {
            // Spare after strike
            isSpare = true;
            this.stats.spares++;
            this.currentRoll = 2;
            this.pinsStanding = new Array(10).fill(true);
          } else {
            if (second === 10) {
              // Two strikes, need third
              this.currentRoll = 2;
              this.pinsStanding = new Array(10).fill(true);
            } else {
              // Check if spare
              if (second + pinsKnockedDown === 10) {
                isSpare = true;
                this.stats.spares++;
                this.currentRoll = 2;
                this.pinsStanding = new Array(10).fill(true);
              } else {
                this.currentRoll = 2;
              }
            }
          }
        } else {
          // Not a strike on first
          if (first + pinsKnockedDown === 10) {
            isSpare = true;
            frame.isSpare = true;
            this.stats.spares++;
            this.currentRoll = 2;
            this.pinsStanding = new Array(10).fill(true);
          } else {
            // No bonus, frame done after 2
            frameComplete = true;
            this.stats.currentStreak = 0;
            this.stats.perfectGame = false;
          }
        }
        // If strike or spare on first+second, need 3rd roll
        if (!frameComplete && (first === 10 || first + second === 10)) {
          // Proceed to 3rd roll
        }
      } else if (rolls.length === 3) {
        if (pinsKnockedDown === 10) {
          isStrike = true;
          this.stats.strikes++;
        }
        frameComplete = true;
      }
    }

    if (frameComplete) {
      this.calculateScores();
      if (this.currentFrame >= 9) {
        gameOver = true;
        this.gameComplete = true;
        this.totalScore = this.getTotalScore();
      } else {
        this.currentFrame++;
        this.currentRoll = 0;
        this.pinsStanding = new Array(10).fill(true);
      }
    } else {
      this.calculateScores();
    }

    const result = { pinsDown: pinsKnockedDown, isStrike, isSpare, frameComplete, gameOver };
    this.emit('rollComplete', result);
    return result;
  }

  private markPinsDown(count: number) {
    // In practice, exact pin positions are determined by physics
    // This is for the scoring logic tracking
    let marked = 0;
    for (let i = 0; i < this.pinsStanding.length && marked < count; i++) {
      if (this.pinsStanding[i]) {
        this.pinsStanding[i] = false;
        marked++;
      }
    }
  }

  /**
   * Standard bowling scoring with look-ahead for strikes/spares.
   */
  calculateScores() {
    // Flatten all rolls
    const allRolls: number[] = [];
    for (const frame of this.frames) {
      allRolls.push(...frame.rolls);
    }

    let rollIndex = 0;
    let cumulative = 0;

    for (let f = 0; f < 10; f++) {
      const frame = this.frames[f];
      if (frame.rolls.length === 0) {
        frame.score = null;
        continue;
      }

      if (f < 9) {
        if (frame.isStrike) {
          // Strike: 10 + next 2 rolls
          if (rollIndex + 2 < allRolls.length) {
            const bonus1 = allRolls[rollIndex + 1];
            const bonus2 = allRolls[rollIndex + 2];
            if (bonus1 !== undefined && bonus2 !== undefined) {
              cumulative += 10 + bonus1 + bonus2;
              frame.score = cumulative;
            } else {
              frame.score = null;
            }
          } else {
            frame.score = null;
          }
          rollIndex += 1;
        } else if (frame.isSpare) {
          // Spare: 10 + next 1 roll
          if (rollIndex + 2 < allRolls.length) {
            const bonus = allRolls[rollIndex + 2];
            if (bonus !== undefined) {
              cumulative += 10 + bonus;
              frame.score = cumulative;
            } else {
              frame.score = null;
            }
          } else {
            frame.score = null;
          }
          rollIndex += 2;
        } else {
          // Normal
          if (frame.rolls.length >= 2) {
            cumulative += frame.rolls[0] + frame.rolls[1];
            frame.score = cumulative;
          } else {
            frame.score = null;
          }
          rollIndex += 2;
        }
      } else {
        // 10th frame: sum all rolls (up to 3)
        const sum = frame.rolls.reduce((a, b) => a + b, 0);
        cumulative += sum;
        frame.score = frame.rolls.length >= 2 &&
          (frame.rolls[0] === 10 || frame.rolls[0] + frame.rolls[1] === 10
            ? frame.rolls.length === 3
            : true)
          ? cumulative
          : null;
        rollIndex += frame.rolls.length;
      }
    }

    this.totalScore = cumulative;
  }

  getTotalScore(): number {
    let total = 0;
    for (const frame of this.frames) {
      if (frame.score !== null) total = frame.score;
    }
    return total;
  }

  getFrameDisplay(frameIndex: number): string {
    const frame = this.frames[frameIndex];
    if (frame.rolls.length === 0) return '';
    if (frameIndex < 9) {
      if (frame.isStrike) return 'X';
      if (frame.isSpare) return `${frame.rolls[0]}/${frame.score !== null ? '' : ''}`;
      if (frame.rolls.length === 1) return `${frame.rolls[0]}`;
      return `${frame.rolls[0]}${frame.rolls[1] === 0 ? '-' : frame.rolls[1]}`;
    }
    // 10th frame
    let display = '';
    for (let i = 0; i < frame.rolls.length; i++) {
      const r = frame.rolls[i];
      if (r === 10) {
        display += 'X';
      } else if (i > 0 && frame.rolls[i - 1] !== 10 && frame.rolls[i - 1] + r === 10) {
        display += '/';
      } else if (r === 0) {
        display += '-';
      } else {
        display += r.toString();
      }
    }
    return display;
  }

  getPinsStanding(): number {
    return this.pinsStanding.filter(p => p).length;
  }

  needsSecondRoll(): boolean {
    if (this.currentFrame < 9) {
      return this.currentRoll === 1;
    }
    return this.frames[9].rolls.length > 0 && !this.gameComplete;
  }

  needsPinReset(): boolean {
    if (this.currentFrame < 9) {
      return this.currentRoll === 0;
    }
    // 10th frame: reset after strike
    const rolls = this.frames[9].rolls;
    if (rolls.length === 1 && rolls[0] === 10) return true;
    if (rolls.length === 2 && rolls[0] === 10 && rolls[1] === 10) return true;
    if (rolls.length === 2 && rolls[0] + rolls[1] === 10) return true;
    return false;
  }
}

/**
 * Astro Bowl VR — Ball System
 * Ball physics, rolling, gutter detection, throwing mechanics, ball types.
 * VR: grip to grab, track controller velocity, trigger release to throw.
 * Browser: click-drag aim, hold to charge power, release to throw.
 */
import {
  Group, Mesh, SphereGeometry, CylinderGeometry,
  MeshStandardMaterial, MeshBasicMaterial, LineBasicMaterial,
  EdgesGeometry, LineSegments, Color, Vector3, Quaternion,
  AdditiveBlending, BufferGeometry, Float32BufferAttribute,
} from '@iwsdk/core';
import { LANE } from './lane';

export interface BallType {
  name: string;
  description: string;
  mass: number;
  speedMult: number;
  hookStrength: number; // 0 = straight, 1 = heavy hook
  color: Color;
  emissive: Color;
  special: string; // special behavior
}

export const BALL_TYPES: Record<string, BallType> = {
  standard: {
    name: 'Standard',
    description: 'Well-balanced ball for all situations',
    mass: 6.35, // ~14 lbs
    speedMult: 1.0,
    hookStrength: 0.0,
    color: new Color(0x00ddff),
    emissive: new Color(0x003344),
    special: 'none',
  },
  heavy: {
    name: 'Heavy',
    description: 'Maximum pin devastation, lower speed',
    mass: 7.26, // ~16 lbs
    speedMult: 0.85,
    hookStrength: 0.0,
    color: new Color(0xff4400),
    emissive: new Color(0x441100),
    special: 'none',
  },
  curve: {
    name: 'Curve',
    description: 'Natural hook for hitting the pocket',
    mass: 6.35,
    speedMult: 0.95,
    hookStrength: 0.6,
    color: new Color(0xaa00ff),
    emissive: new Color(0x220044),
    special: 'none',
  },
  split_seeker: {
    name: 'Split Seeker',
    description: 'Wide break for cleaning up splits',
    mass: 5.9,
    speedMult: 0.9,
    hookStrength: 0.9,
    color: new Color(0x00ff44),
    emissive: new Color(0x004411),
    special: 'none',
  },
  phantom: {
    name: 'Phantom',
    description: 'Phases through front pin, hits the back',
    mass: 6.35,
    speedMult: 1.0,
    hookStrength: 0.0,
    color: new Color(0x8800ff),
    emissive: new Color(0x220044),
    special: 'phantom',
  },
};

const BALL_RADIUS = 0.109; // ~4.3 inches radius
const LANE_FRICTION = 0.985;
const GUTTER_FRICTION = 0.95;

export enum BallState {
  ON_RETURN = 'on_return',
  HELD = 'held',
  ROLLING = 'rolling',
  IN_GUTTER = 'in_gutter',
  AT_PINS = 'at_pins',
  DONE = 'done',
}

export class BallController {
  group: Group;
  mesh: Group;
  position: Vector3;
  velocity: Vector3;
  spin: Vector3;
  state: BallState = BallState.ON_RETURN;
  ballType: BallType;
  private trailPoints: Vector3[] = [];
  private trailMesh: LineSegments;
  private glowMesh: Mesh;
  private rollRotation: number = 0;
  inGutter: boolean = false;
  phantomPhased: boolean = false;
  private phantomPhaseCount: number = 0;

  constructor(ballTypeName: string = 'standard') {
    this.group = new Group();
    this.ballType = BALL_TYPES[ballTypeName] || BALL_TYPES.standard;
    this.position = new Vector3(LANE.BALL_RETURN_X, LANE.SURFACE_Y + BALL_RADIUS + 0.62, LANE.BALL_RETURN_Z);
    this.velocity = new Vector3();
    this.spin = new Vector3();

    this.mesh = this.createBallMesh();
    this.mesh.position.copy(this.position);
    this.group.add(this.mesh);

    this.trailMesh = this.createTrail();
    this.group.add(this.trailMesh);

    this.glowMesh = this.createGlow();
    this.group.add(this.glowMesh);
  }

  private createBallMesh(): Group {
    const ballGroup = new Group();

    // Main ball
    const mat = new MeshStandardMaterial({
      color: this.ballType.color,
      roughness: 0.15,
      metalness: 0.7,
      emissive: this.ballType.emissive,
      emissiveIntensity: 0.3,
    });
    const sphere = new Mesh(new SphereGeometry(BALL_RADIUS, 24, 24), mat);
    ballGroup.add(sphere);

    // Wireframe overlay
    const wireMat = new LineBasicMaterial({
      color: this.ballType.color,
      transparent: true,
      opacity: 0.2,
    });
    const edges = new EdgesGeometry(new SphereGeometry(BALL_RADIUS + 0.001, 12, 12));
    const wire = new LineSegments(edges, wireMat);
    ballGroup.add(wire);

    // Finger holes
    const holeMat = new MeshBasicMaterial({ color: 0x000000 });
    const holeGeo = new CylinderGeometry(0.015, 0.015, 0.02, 8);
    for (let i = 0; i < 3; i++) {
      const hole = new Mesh(holeGeo, holeMat);
      const angle = (i / 3) * Math.PI * 0.6 - 0.3;
      hole.position.set(
        Math.sin(angle) * BALL_RADIUS * 0.5,
        BALL_RADIUS * 0.8,
        Math.cos(angle) * BALL_RADIUS * 0.5,
      );
      hole.lookAt(0, 0, 0);
      ballGroup.add(hole);
    }

    return ballGroup;
  }

  private createTrail(): LineSegments {
    const geo = new BufferGeometry();
    const positions = new Float32Array(300); // 100 points * 3
    geo.setAttribute('position', new Float32BufferAttribute(positions, 3));
    const mat = new LineBasicMaterial({
      color: this.ballType.color,
      transparent: true,
      opacity: 0.4,
      blending: AdditiveBlending,
    });
    const trail = new LineSegments(geo, mat);
    trail.frustumCulled = false;
    return trail;
  }

  private createGlow(): Mesh {
    const mat = new MeshBasicMaterial({
      color: this.ballType.color,
      transparent: true,
      opacity: 0.15,
      blending: AdditiveBlending,
    });
    return new Mesh(new SphereGeometry(BALL_RADIUS * 1.8, 16, 16), mat);
  }

  setBallType(typeName: string) {
    const newType = BALL_TYPES[typeName];
    if (!newType) return;
    this.ballType = newType;

    // Update ball visuals
    this.group.remove(this.mesh);
    this.mesh = this.createBallMesh();
    this.mesh.position.copy(this.position);
    this.group.add(this.mesh);

    // Update trail and glow colors
    (this.trailMesh.material as LineBasicMaterial).color.copy(newType.color);
    (this.glowMesh.material as MeshBasicMaterial).color.copy(newType.color);
  }

  resetToReturn() {
    this.position.set(LANE.BALL_RETURN_X, LANE.SURFACE_Y + BALL_RADIUS + 0.62, LANE.BALL_RETURN_Z);
    this.velocity.set(0, 0, 0);
    this.spin.set(0, 0, 0);
    this.state = BallState.ON_RETURN;
    this.inGutter = false;
    this.phantomPhased = false;
    this.phantomPhaseCount = 0;
    this.mesh.position.copy(this.position);
    this.glowMesh.position.copy(this.position);
    this.trailPoints = [];
    this.mesh.visible = true;
    this.rollRotation = 0;
  }

  /**
   * Throw the ball with a given velocity vector.
   */
  throw(velocity: Vector3) {
    this.state = BallState.ROLLING;
    this.velocity.copy(velocity);
    this.velocity.multiplyScalar(this.ballType.speedMult);
    this.position.set(
      Math.max(-LANE.LANE_WIDTH / 2 + BALL_RADIUS, Math.min(LANE.LANE_WIDTH / 2 - BALL_RADIUS, this.position.x)),
      LANE.SURFACE_Y + BALL_RADIUS,
      LANE.FOUL_LINE_Z - 0.1,
    );
    this.inGutter = false;
    this.trailPoints = [];
  }

  /**
   * Update ball physics each frame. Returns true if ball reached pin area or is done.
   */
  update(dt: number): { reachedPins: boolean; inGutter: boolean; done: boolean } {
    if (this.state === BallState.ON_RETURN || this.state === BallState.HELD || this.state === BallState.DONE) {
      this.glowMesh.position.copy(this.position);
      return { reachedPins: false, inGutter: false, done: this.state === BallState.DONE };
    }

    // Apply hook (curve effect)
    if (this.ballType.hookStrength > 0 && !this.inGutter) {
      const hookForce = this.ballType.hookStrength * 0.5;
      // Hook breaks left for right-handers (negative x)
      this.velocity.x -= hookForce * dt * Math.sign(this.velocity.z || -1);
    }

    // Update position
    this.position.x += this.velocity.x * dt;
    this.position.z += this.velocity.z * dt;

    // Friction
    const friction = this.inGutter ? GUTTER_FRICTION : LANE_FRICTION;
    this.velocity.x *= friction;
    this.velocity.z *= friction;

    // Keep ball on lane surface
    this.position.y = this.inGutter
      ? LANE.SURFACE_Y - LANE.GUTTER_DEPTH + BALL_RADIUS
      : LANE.SURFACE_Y + BALL_RADIUS;

    // Gutter detection
    const halfLane = LANE.LANE_WIDTH / 2;
    if (!this.inGutter && Math.abs(this.position.x) > halfLane) {
      this.inGutter = true;
      this.state = BallState.IN_GUTTER;
    }

    // Keep in gutter bounds
    if (this.inGutter) {
      const gutterEdge = halfLane + LANE.GUTTER_WIDTH;
      if (Math.abs(this.position.x) > gutterEdge) {
        this.position.x = Math.sign(this.position.x) * gutterEdge;
        this.velocity.x = 0;
      }
    }

    // Ball rotation (visual rolling effect)
    const speed = Math.sqrt(this.velocity.x ** 2 + this.velocity.z ** 2);
    this.rollRotation += speed * dt * 10;
    this.mesh.rotation.x = this.rollRotation;

    // Trail
    if (speed > 0.1) {
      this.trailPoints.push(this.position.clone());
      if (this.trailPoints.length > 80) this.trailPoints.shift();
      this.updateTrail();
    }

    // Phantom ball special behavior
    if (this.ballType.special === 'phantom' && !this.phantomPhased) {
      // Phase through front pin area (headpin)
      if (this.position.z < LANE.HEADPIN_Z + 0.2 && this.position.z > LANE.HEADPIN_Z - 0.2) {
        // Make ball semi-transparent
        this.mesh.traverse(child => {
          if (child instanceof Mesh) {
            const mat = child.material as any;
            if (mat.opacity !== undefined) mat.opacity = 0.3;
            mat.transparent = true;
          }
        });
        this.phantomPhased = true;
      }
    }

    // Check if reached pin area
    const reachedPins = this.position.z <= LANE.HEADPIN_Z + 0.3 && !this.inGutter;

    // Check if ball is past backstop or stopped
    const done = this.position.z < LANE.BACKSTOP_Z - 0.5 || speed < 0.05;

    if (done) {
      this.state = BallState.DONE;
    }

    // Update mesh position
    this.mesh.position.copy(this.position);
    this.glowMesh.position.copy(this.position);

    // Glow intensity based on speed
    const glowIntensity = Math.min(0.3, speed * 0.05);
    (this.glowMesh.material as MeshBasicMaterial).opacity = glowIntensity;

    return { reachedPins, inGutter: this.inGutter, done };
  }

  private updateTrail() {
    if (this.trailPoints.length < 2) return;
    const positions: number[] = [];
    for (let i = 0; i < this.trailPoints.length - 1; i++) {
      const p1 = this.trailPoints[i];
      const p2 = this.trailPoints[i + 1];
      positions.push(p1.x, p1.y, p1.z, p2.x, p2.y, p2.z);
    }

    const geo = this.trailMesh.geometry;
    const posAttr = geo.getAttribute('position');
    const arr = posAttr.array as Float32Array;
    arr.fill(0);
    for (let i = 0; i < Math.min(positions.length, arr.length); i++) {
      arr[i] = positions[i];
    }
    posAttr.needsUpdate = true;
    geo.setDrawRange(0, Math.min(positions.length / 3, 200));
  }

  getRadius(): number {
    return BALL_RADIUS;
  }
}

/**
 * Astro Bowl VR — Pin System
 * 10 pins with proper triangular arrangement, physics simulation,
 * fall/scatter/topple, sweep animation, holographic respawn.
 */
import {
  Group, Mesh, CylinderGeometry, SphereGeometry, BoxGeometry,
  MeshStandardMaterial, MeshBasicMaterial, LineBasicMaterial,
  EdgesGeometry, LineSegments, Color, Vector3, Quaternion,
  AdditiveBlending,
} from '@iwsdk/core';
import { LANE } from './lane';

export interface PinState {
  index: number;
  standing: boolean;
  position: Vector3;
  velocity: Vector3;
  angularVelocity: Vector3;
  rotation: { x: number; y: number; z: number };
  settleTimer: number;
  mesh: Group;
  originalPosition: Vector3;
}

const PIN_HEIGHT = 0.38;
const PIN_RADIUS_BASE = 0.057;
const PIN_RADIUS_NECK = 0.03;
const PIN_RADIUS_HEAD = 0.045;
const PIN_MASS = 1.5; // kg
const GRAVITY = -9.81;
const FLOOR_Y = LANE.SURFACE_Y;
const SETTLE_THRESHOLD = 0.01;
const SETTLE_TIME = 0.5; // seconds to consider settled
const FRICTION = 0.7;
const RESTITUTION = 0.3;
const PIN_PIN_RESTITUTION = 0.5;

export class PinManager {
  group: Group;
  pins: PinState[] = [];
  private primaryColor: Color;
  private accentColor: Color;
  sweepInProgress: boolean = false;
  private sweepProgress: number = 0;
  private sweepBar: Mesh;
  private respawnTimer: number = 0;
  private respawnPhase: 'idle' | 'sweep' | 'clear' | 'respawn' = 'idle';
  allSettled: boolean = false;

  constructor(primaryColor: Color, accentColor: Color) {
    this.primaryColor = primaryColor;
    this.accentColor = accentColor;
    this.group = new Group();
    this.createSweepBar();
    this.resetPins();
  }

  private createPinMesh(index: number): Group {
    const pinGroup = new Group();

    // Pin body (simplified bowling pin shape using multiple cylinders)
    // Base (wide)
    const baseMat = new MeshStandardMaterial({
      color: 0xeeeeee,
      roughness: 0.2,
      metalness: 0.4,
      emissive: this.primaryColor,
      emissiveIntensity: 0.05,
    });
    const base = new Mesh(new CylinderGeometry(PIN_RADIUS_BASE, PIN_RADIUS_BASE * 1.1, PIN_HEIGHT * 0.35, 12), baseMat);
    base.position.y = PIN_HEIGHT * 0.175;
    pinGroup.add(base);

    // Neck (narrow)
    const neck = new Mesh(
      new CylinderGeometry(PIN_RADIUS_NECK, PIN_RADIUS_BASE, PIN_HEIGHT * 0.3, 12),
      baseMat.clone(),
    );
    neck.position.y = PIN_HEIGHT * 0.5;
    pinGroup.add(neck);

    // Head (wider top)
    const head = new Mesh(
      new CylinderGeometry(PIN_RADIUS_HEAD * 0.6, PIN_RADIUS_HEAD, PIN_HEIGHT * 0.25, 12),
      baseMat.clone(),
    );
    head.position.y = PIN_HEIGHT * 0.775;
    pinGroup.add(head);

    // Red stripe
    const stripeMat = new MeshBasicMaterial({
      color: 0xff2244,
      transparent: true,
      opacity: 0.8,
    });
    const stripe = new Mesh(new CylinderGeometry(PIN_RADIUS_NECK + 0.002, PIN_RADIUS_NECK + 0.002, 0.025, 12), stripeMat);
    stripe.position.y = PIN_HEIGHT * 0.58;
    pinGroup.add(stripe);

    const stripe2 = new Mesh(new CylinderGeometry(PIN_RADIUS_NECK + 0.002, PIN_RADIUS_NECK + 0.002, 0.025, 12), stripeMat.clone());
    stripe2.position.y = PIN_HEIGHT * 0.63;
    pinGroup.add(stripe2);

    // Wireframe overlay for holodeck aesthetic
    const wireMat = new LineBasicMaterial({
      color: this.primaryColor,
      transparent: true,
      opacity: 0.15,
    });
    for (const child of [base, neck, head]) {
      const edges = new EdgesGeometry(child.geometry);
      const wireframe = new LineSegments(edges, wireMat);
      wireframe.position.copy(child.position);
      pinGroup.add(wireframe);
    }

    // Number label (flat mesh on the pin)
    // Simplified — just a dot marker for identification
    const dotMat = new MeshBasicMaterial({
      color: this.accentColor,
      transparent: true,
      opacity: 0.5,
    });
    const dot = new Mesh(new SphereGeometry(0.008, 6, 6), dotMat);
    dot.position.set(0, PIN_HEIGHT * 0.65, PIN_RADIUS_NECK + 0.01);
    pinGroup.add(dot);

    return pinGroup;
  }

  private createSweepBar() {
    const barMat = new MeshStandardMaterial({
      color: 0x333366,
      roughness: 0.3,
      metalness: 0.8,
      transparent: true,
      opacity: 0.8,
    });
    this.sweepBar = new Mesh(
      new BoxGeometry(LANE.LANE_WIDTH + LANE.GUTTER_WIDTH * 2, 0.5, 0.05),
      barMat,
    );
    this.sweepBar.position.set(0, 5, LANE.HEADPIN_Z);
    this.sweepBar.visible = false;
    this.group.add(this.sweepBar);

    // Wireframe
    const edges = new EdgesGeometry(this.sweepBar.geometry);
    const edgeMat = new LineBasicMaterial({ color: this.primaryColor, transparent: true, opacity: 0.5 });
    const wire = new LineSegments(edges, edgeMat);
    this.sweepBar.add(wire);
  }

  resetPins(onlyStanding: boolean = false) {
    // Remove existing pin meshes
    if (!onlyStanding) {
      for (const pin of this.pins) {
        this.group.remove(pin.mesh);
      }
      this.pins = [];
    }

    const positions = this.getPinPositions();

    if (onlyStanding) {
      // Just reset positions of standing pins
      for (const pin of this.pins) {
        if (pin.standing) {
          pin.position.copy(pin.originalPosition);
          pin.velocity.set(0, 0, 0);
          pin.angularVelocity.set(0, 0, 0);
          pin.rotation = { x: 0, y: 0, z: 0 };
          pin.settleTimer = 0;
          pin.mesh.position.copy(pin.originalPosition);
          pin.mesh.rotation.set(0, 0, 0);
        }
      }
      return;
    }

    for (let i = 0; i < 10; i++) {
      const mesh = this.createPinMesh(i);
      const pos = new Vector3(positions[i].x, FLOOR_Y, positions[i].z);
      mesh.position.copy(pos);

      const pinState: PinState = {
        index: i,
        standing: true,
        position: pos.clone(),
        velocity: new Vector3(),
        angularVelocity: new Vector3(),
        rotation: { x: 0, y: 0, z: 0 },
        settleTimer: 0,
        mesh,
        originalPosition: pos.clone(),
      };

      this.pins.push(pinState);
      this.group.add(mesh);
    }
    this.allSettled = true;
  }

  private getPinPositions(): { x: number; z: number }[] {
    const sp = LANE.PIN_SPACING;
    const startZ = LANE.HEADPIN_Z;
    return [
      { x: 0, z: startZ },
      { x: -sp / 2, z: startZ - sp * 0.866 },
      { x: sp / 2, z: startZ - sp * 0.866 },
      { x: -sp, z: startZ - sp * 0.866 * 2 },
      { x: 0, z: startZ - sp * 0.866 * 2 },
      { x: sp, z: startZ - sp * 0.866 * 2 },
      { x: -sp * 1.5, z: startZ - sp * 0.866 * 3 },
      { x: -sp / 2, z: startZ - sp * 0.866 * 3 },
      { x: sp / 2, z: startZ - sp * 0.866 * 3 },
      { x: sp * 1.5, z: startZ - sp * 0.866 * 3 },
    ];
  }

  /**
   * Apply ball collision to pins.
   * Returns number of pins knocked down.
   */
  applyBallImpact(ballPos: Vector3, ballVelocity: Vector3, ballRadius: number, ballMass: number): number {
    let knockedDown = 0;

    for (const pin of this.pins) {
      if (!pin.standing) continue;

      const dist = new Vector3(
        pin.position.x - ballPos.x,
        0,
        pin.position.z - ballPos.z,
      ).length();

      const hitRadius = ballRadius + PIN_RADIUS_BASE;

      if (dist < hitRadius) {
        // Direct hit
        const impactDir = new Vector3(
          pin.position.x - ballPos.x,
          0,
          pin.position.z - ballPos.z,
        ).normalize();

        // Impulse based on ball velocity and mass
        const impulseMag = ballMass * ballVelocity.length() * 0.8;
        pin.velocity.x += impactDir.x * impulseMag * 0.5 + ballVelocity.x * 0.3;
        pin.velocity.z += impactDir.z * impulseMag * 0.5 + ballVelocity.z * 0.3;
        pin.velocity.y += 1.5 + Math.random() * 2;

        // Angular velocity from off-center hit
        pin.angularVelocity.x += (Math.random() - 0.5) * 8;
        pin.angularVelocity.z += impactDir.x * 5;

        pin.standing = false;
        pin.settleTimer = 0;
        knockedDown++;
      }
    }

    // Pin-to-pin chain reactions
    this.resolveChainReactions();
    return knockedDown;
  }

  private resolveChainReactions() {
    const iterations = 3;
    for (let iter = 0; iter < iterations; iter++) {
      for (let i = 0; i < this.pins.length; i++) {
        const pinA = this.pins[i];
        if (pinA.standing) continue; // Only fallen pins can knock others

        for (let j = 0; j < this.pins.length; j++) {
          if (i === j) continue;
          const pinB = this.pins[j];
          if (!pinB.standing) continue;

          const dist = new Vector3(
            pinB.position.x - pinA.position.x,
            0,
            pinB.position.z - pinA.position.z,
          ).length();

          const chainRadius = PIN_RADIUS_BASE * 3;
          if (dist < chainRadius && pinA.velocity.length() > 0.5) {
            const dir = new Vector3(
              pinB.position.x - pinA.position.x,
              0,
              pinB.position.z - pinA.position.z,
            ).normalize();

            const transferSpeed = pinA.velocity.length() * PIN_PIN_RESTITUTION;
            pinB.velocity.x += dir.x * transferSpeed;
            pinB.velocity.z += dir.z * transferSpeed;
            pinB.velocity.y += 0.8 + Math.random();
            pinB.angularVelocity.x += (Math.random() - 0.5) * 5;
            pinB.angularVelocity.z += dir.x * 3;
            pinB.standing = false;
          }
        }
      }
    }
  }

  /**
   * Update pin physics each frame.
   */
  updatePhysics(dt: number) {
    this.allSettled = true;

    for (const pin of this.pins) {
      if (pin.standing) continue;

      // Gravity
      pin.velocity.y += GRAVITY * dt;

      // Update position
      pin.position.x += pin.velocity.x * dt;
      pin.position.y += pin.velocity.y * dt;
      pin.position.z += pin.velocity.z * dt;

      // Update rotation
      pin.rotation.x += pin.angularVelocity.x * dt;
      pin.rotation.z += pin.angularVelocity.z * dt;

      // Floor collision
      if (pin.position.y < FLOOR_Y) {
        pin.position.y = FLOOR_Y;
        pin.velocity.y *= -RESTITUTION;
        if (Math.abs(pin.velocity.y) < 0.1) pin.velocity.y = 0;

        // Friction
        pin.velocity.x *= FRICTION;
        pin.velocity.z *= FRICTION;
        pin.angularVelocity.x *= FRICTION;
        pin.angularVelocity.z *= FRICTION;
      }

      // Lane boundaries
      const halfLane = LANE.LANE_WIDTH / 2 + LANE.GUTTER_WIDTH + 0.3;
      if (Math.abs(pin.position.x) > halfLane) {
        pin.position.x = Math.sign(pin.position.x) * halfLane;
        pin.velocity.x *= -0.3;
      }

      // Backstop collision
      if (pin.position.z < LANE.BACKSTOP_Z) {
        pin.position.z = LANE.BACKSTOP_Z;
        pin.velocity.z *= -0.3;
      }

      // Check if settled
      const speed = pin.velocity.length() + Math.abs(pin.angularVelocity.x) + Math.abs(pin.angularVelocity.z);
      if (speed < SETTLE_THRESHOLD) {
        pin.settleTimer += dt;
        if (pin.settleTimer > SETTLE_TIME) {
          pin.velocity.set(0, 0, 0);
          pin.angularVelocity.set(0, 0, 0);
        } else {
          this.allSettled = false;
        }
      } else {
        pin.settleTimer = 0;
        this.allSettled = false;
      }

      // Update mesh
      pin.mesh.position.copy(pin.position);
      pin.mesh.rotation.set(pin.rotation.x, 0, pin.rotation.z);
    }
  }

  /**
   * Count how many pins are currently standing.
   */
  countStanding(): number {
    return this.pins.filter(p => p.standing).length;
  }

  /**
   * Count how many pins were knocked down (from original 10 or remaining).
   */
  countKnockedDown(): number {
    return this.pins.filter(p => !p.standing).length;
  }

  /**
   * Start the sweep animation to clear fallen pins.
   */
  startSweep(resetAll: boolean = true, onComplete?: () => void) {
    this.sweepInProgress = true;
    this.respawnPhase = 'sweep';
    this.sweepProgress = 0;
    this.sweepBar.visible = true;
    this.sweepBar.position.y = 1.0;
    this.sweepBar.position.z = LANE.HEADPIN_Z + 2;

    const animate = () => {
      this.sweepProgress += 0.02;
      if (this.sweepProgress < 1) {
        // Sweep bar moves across pin area
        this.sweepBar.position.z = LANE.HEADPIN_Z + 2 - this.sweepProgress * 4;
        this.sweepBar.position.y = 0.25;

        // Hide fallen pins as sweep bar passes
        for (const pin of this.pins) {
          if (!pin.standing && pin.position.z > this.sweepBar.position.z - 0.5) {
            pin.mesh.visible = false;
          }
        }
        requestAnimationFrame(animate);
      } else {
        // Sweep complete
        this.sweepBar.visible = false;
        this.respawnPhase = 'respawn';
        this.respawnTimer = 0;

        if (resetAll) {
          this.resetPins();
        } else {
          // Remove fallen pins, keep standing
          for (const pin of this.pins) {
            if (!pin.standing) {
              this.group.remove(pin.mesh);
            }
          }
          this.pins = this.pins.filter(p => p.standing);
        }

        // Holographic respawn effect
        if (resetAll) {
          this.playRespawnEffect();
        }

        this.sweepInProgress = false;
        if (onComplete) onComplete();
      }
    };
    requestAnimationFrame(animate);
  }

  private playRespawnEffect() {
    // Holographic materialization: pins start transparent, flicker in
    for (const pin of this.pins) {
      pin.mesh.traverse(child => {
        if (child instanceof Mesh) {
          const mat = child.material as MeshStandardMaterial | MeshBasicMaterial;
          if (mat.transparent !== undefined) {
            mat.transparent = true;
            mat.opacity = 0;
          }
        }
      });
    }

    let progress = 0;
    const fadeIn = () => {
      progress += 0.03;
      if (progress < 1) {
        const flicker = Math.random() > 0.3 ? progress : progress * 0.5;
        for (const pin of this.pins) {
          pin.mesh.traverse(child => {
            if (child instanceof Mesh) {
              const mat = child.material as any;
              if (mat.opacity !== undefined) {
                mat.opacity = Math.min(flicker, mat.userData?.targetOpacity ?? 1);
              }
            }
          });
        }
        requestAnimationFrame(fadeIn);
      } else {
        // Fully visible
        for (const pin of this.pins) {
          pin.mesh.traverse(child => {
            if (child instanceof Mesh) {
              const mat = child.material as any;
              mat.opacity = 1;
              mat.transparent = false;
            }
          });
        }
        this.respawnPhase = 'idle';
      }
    };
    requestAnimationFrame(fadeIn);
  }
}

/**
 * Astro Bowl VR — Environment
 * Holodeck arena: neon grid floor, fog, ambient lights, ceiling grid, walls.
 */
import {
  Group, Mesh, PlaneGeometry, BoxGeometry, SphereGeometry,
  MeshBasicMaterial, MeshStandardMaterial, LineBasicMaterial,
  EdgesGeometry, LineSegments, Color, Fog, AmbientLight,
  DirectionalLight, PointLight, Vector3, DoubleSide,
  AdditiveBlending, CylinderGeometry, Float32BufferAttribute,
  BufferGeometry, TorusGeometry, RingGeometry,
} from '@iwsdk/core';

export interface ThemeColors {
  primary: Color;
  secondary: Color;
  accent: Color;
  fog: Color;
  ambient: Color;
  grid: Color;
  name: string;
}

export const THEMES: Record<string, ThemeColors> = {
  neon_circuit: {
    name: 'Neon Circuit',
    primary: new Color(0x00ffff),
    secondary: new Color(0xff00ff),
    accent: new Color(0xffff00),
    fog: new Color(0x000a14),
    ambient: new Color(0x001122),
    grid: new Color(0x00ffff),
  },
  starfield: {
    name: 'Starfield',
    primary: new Color(0x4488ff),
    secondary: new Color(0xffffff),
    accent: new Color(0x88ccff),
    fog: new Color(0x000008),
    ambient: new Color(0x000811),
    grid: new Color(0x2244aa),
  },
  quantum_grid: {
    name: 'Quantum Grid',
    primary: new Color(0x00ff88),
    secondary: new Color(0xaa00ff),
    accent: new Color(0xff4400),
    fog: new Color(0x000a04),
    ambient: new Color(0x001108),
    grid: new Color(0x00ff88),
  },
};

export class EnvironmentBuilder {
  group: Group;
  theme: ThemeColors;
  private particles: Mesh[] = [];
  private gridFloor: LineSegments;
  private ceilingGrid: LineSegments;
  private wallPanels: Mesh[] = [];
  private lights: PointLight[] = [];

  constructor(theme: string = 'neon_circuit') {
    this.group = new Group();
    this.theme = THEMES[theme] || THEMES.neon_circuit;
    this.buildEnvironment();
  }

  private buildEnvironment() {
    // Grid floor
    this.gridFloor = this.createGrid(60, 80, 1, this.theme.grid, 0.3);
    this.gridFloor.position.y = -0.01;
    this.gridFloor.rotation.x = -Math.PI / 2;
    this.group.add(this.gridFloor);

    // Ceiling grid
    this.ceilingGrid = this.createGrid(60, 80, 2, this.theme.grid, 0.15);
    this.ceilingGrid.position.y = 8;
    this.ceilingGrid.rotation.x = -Math.PI / 2;
    this.group.add(this.ceilingGrid);

    // Side walls (translucent panels)
    this.createWalls();

    // Ambient lights
    const ambient = new AmbientLight(this.theme.ambient, 0.4);
    this.group.add(ambient);

    const dir = new DirectionalLight(0xffffff, 0.3);
    dir.position.set(5, 10, 5);
    this.group.add(dir);

    // Neon accent lights along the lane
    for (let z = 0; z > -20; z -= 4) {
      const lightLeft = new PointLight(this.theme.primary.getHex(), 0.6, 12);
      lightLeft.position.set(-5, 3, z);
      this.group.add(lightLeft);
      this.lights.push(lightLeft);

      const lightRight = new PointLight(this.theme.secondary.getHex(), 0.6, 12);
      lightRight.position.set(5, 3, z);
      this.group.add(lightRight);
      this.lights.push(lightRight);
    }

    // Floating ambient particles
    this.createFloatingParticles();

    // Holographic decorative elements
    this.createDecorations();
  }

  private createGrid(width: number, depth: number, spacing: number, color: Color, opacity: number): LineSegments {
    const points: number[] = [];
    const halfW = width / 2;
    const halfD = depth / 2;

    // Lines along X
    for (let z = -halfD; z <= halfD; z += spacing) {
      points.push(-halfW, 0, z, halfW, 0, z);
    }
    // Lines along Z
    for (let x = -halfW; x <= halfW; x += spacing) {
      points.push(x, 0, -halfD, x, 0, halfD);
    }

    const geo = new BufferGeometry();
    geo.setAttribute('position', new Float32BufferAttribute(points, 3));
    const mat = new LineBasicMaterial({
      color,
      transparent: true,
      opacity,
    });
    return new LineSegments(geo, mat);
  }

  private createWalls() {
    const wallMat = new MeshBasicMaterial({
      color: this.theme.primary,
      transparent: true,
      opacity: 0.05,
      side: DoubleSide,
    });

    // Left wall
    const leftWall = new Mesh(new PlaneGeometry(80, 8), wallMat);
    leftWall.position.set(-12, 4, -20);
    leftWall.rotation.y = Math.PI / 2;
    this.group.add(leftWall);
    this.wallPanels.push(leftWall);

    // Right wall
    const rightWall = new Mesh(new PlaneGeometry(80, 8), wallMat.clone());
    rightWall.position.set(12, 4, -20);
    rightWall.rotation.y = -Math.PI / 2;
    this.group.add(rightWall);
    this.wallPanels.push(rightWall);

    // Wall edge lines
    const edgeMat = new LineBasicMaterial({ color: this.theme.primary, transparent: true, opacity: 0.4 });
    for (const wall of this.wallPanels) {
      const edges = new EdgesGeometry(wall.geometry);
      const edgeLines = new LineSegments(edges, edgeMat);
      edgeLines.position.copy(wall.position);
      edgeLines.rotation.copy(wall.rotation);
      this.group.add(edgeLines);
    }
  }

  private createFloatingParticles() {
    const colors = [this.theme.primary, this.theme.secondary, this.theme.accent];
    for (let i = 0; i < 40; i++) {
      const size = 0.03 + Math.random() * 0.06;
      const geo = new SphereGeometry(size, 6, 6);
      const mat = new MeshBasicMaterial({
        color: colors[i % 3],
        transparent: true,
        opacity: 0.3 + Math.random() * 0.4,
        blending: AdditiveBlending,
      });
      const particle = new Mesh(geo, mat);
      particle.position.set(
        (Math.random() - 0.5) * 20,
        1 + Math.random() * 6,
        -Math.random() * 25,
      );
      particle.userData.floatSpeed = 0.3 + Math.random() * 0.5;
      particle.userData.floatOffset = Math.random() * Math.PI * 2;
      particle.userData.driftX = (Math.random() - 0.5) * 0.2;
      this.group.add(particle);
      this.particles.push(particle);
    }
  }

  private createDecorations() {
    // Floating holographic shapes
    const shapes = [
      new BoxGeometry(0.4, 0.4, 0.4),
      new SphereGeometry(0.25, 8, 8),
      new TorusGeometry(0.3, 0.08, 8, 16),
      new CylinderGeometry(0.2, 0.2, 0.5, 8),
    ];

    for (let i = 0; i < 12; i++) {
      const geo = shapes[i % shapes.length];
      const edgeGeo = new EdgesGeometry(geo);
      const mat = new LineBasicMaterial({
        color: i % 2 === 0 ? this.theme.primary : this.theme.secondary,
        transparent: true,
        opacity: 0.2 + Math.random() * 0.3,
      });
      const wireShape = new LineSegments(edgeGeo, mat);
      const side = i % 2 === 0 ? -1 : 1;
      wireShape.position.set(
        side * (6 + Math.random() * 4),
        2 + Math.random() * 4,
        -Math.random() * 20,
      );
      wireShape.userData.rotSpeed = (Math.random() - 0.5) * 0.5;
      wireShape.userData.floatSpeed = 0.2 + Math.random() * 0.3;
      wireShape.userData.floatOffset = Math.random() * Math.PI * 2;
      this.group.add(wireShape);
    }
  }

  applyTheme(themeName: string) {
    const theme = THEMES[themeName];
    if (!theme) return;
    this.theme = theme;

    // Update grid colors
    (this.gridFloor.material as LineBasicMaterial).color.copy(theme.grid);
    (this.ceilingGrid.material as LineBasicMaterial).color.copy(theme.grid);

    // Update wall colors
    for (const wall of this.wallPanels) {
      (wall.material as MeshBasicMaterial).color.copy(theme.primary);
    }

    // Update lights
    const lightColors = [theme.primary, theme.secondary];
    this.lights.forEach((light, i) => {
      light.color.copy(lightColors[i % 2]);
    });
  }

  update(time: number) {
    // Animate floating particles
    for (const p of this.particles) {
      const t = time * p.userData.floatSpeed + p.userData.floatOffset;
      p.position.y += Math.sin(t) * 0.002;
      p.position.x += p.userData.driftX * 0.001;
    }

    // Animate decorative wireframes
    this.group.children.forEach(child => {
      if (child instanceof LineSegments && child.userData.rotSpeed) {
        child.rotation.x += child.userData.rotSpeed * 0.01;
        child.rotation.y += child.userData.rotSpeed * 0.015;
        const ft = time * child.userData.floatSpeed + child.userData.floatOffset;
        child.position.y += Math.sin(ft) * 0.001;
      }
    });
  }
}

/**
 * Astro Bowl VR — HUD System
 * Bowling scorecard, current frame indicator, pins remaining, power meter.
 */
export class HUDManager {
  private container: HTMLDivElement;
  private scorecard: HTMLDivElement;
  private frameIndicator: HTMLDivElement;
  private pinDisplay: HTMLDivElement;
  private powerBar: HTMLDivElement;
  private messageDisplay: HTMLDivElement;
  private visible: boolean = false;

  constructor() {
