      themesHtml += `
        <div class="theme-card${sel}" onclick="window.__themeSelect('${key}')">
          <div style="width:20px;height:20px;border-radius:50%;background:${colorHex};margin:0 auto 6px;box-shadow:0 0 8px ${colorHex}"></div>
          <div style="color:#fff;font-size:12px">${t.name}</div>
        </div>
      `;
    }

    panel.innerHTML = `
      <div class="ui-section-title">SETTINGS</div>
      <div class="settings-row">
        <span>Music Volume</span>
        <input type="range" class="settings-slider" min="0" max="100" value="${musicVol * 100}" oninput="window.__setMusic(this.value)">
      </div>
      <div class="settings-row">
        <span>SFX Volume</span>
        <input type="range" class="settings-slider" min="0" max="100" value="${sfxVol * 100}" oninput="window.__setSfx(this.value)">
      </div>
      <div style="margin-top:16px;color:rgba(255,255,255,0.6);font-size:13px">Lane Theme</div>
      <div class="theme-grid">${themesHtml}</div>
      <button class="ui-btn" onclick="window.__ui.backToTitle()">← BACK</button>
    `;

    (window as any).__setMusic = (val: string) => {
      const v = parseInt(val) / 100;
      musicVol = v;
      // Will be picked up by the app
      if ((window as any).__onMusicVolChange) (window as any).__onMusicVolChange(v);
    };
    (window as any).__setSfx = (val: string) => {
      const v = parseInt(val) / 100;
      sfxVol = v;
      if ((window as any).__onSfxVolChange) (window as any).__onSfxVolChange(v);
    };
    (window as any).__themeSelect = (key: string) => {
      this.onThemeSelect(key);
      this.showSettings(musicVol, sfxVol, key);
    };
    (window as any).__ui.backToTitle = () => this.showTitleScreen();

    this.showPanel('ui-settings');
  }

  showGameOver(score: number, stats: { strikes: number; spares: number; gutters: number; totalPins: number; maxStreak: number }) {
    const panel = document.getElementById('ui-game-over')!;
    const rating = score >= 300 ? '⭐ PERFECT GAME!' :
                   score >= 250 ? '🏆 AMAZING!' :
                   score >= 200 ? '🎯 GREAT!' :
                   score >= 150 ? '👍 GOOD GAME' : '🎳 KEEP BOWLING';

    panel.innerHTML = `
      <div class="ui-section-title">GAME OVER</div>
      <div class="game-over-label">FINAL SCORE</div>
      <div class="game-over-score">${score}</div>
      <div style="color:rgba(255,255,255,0.6);font-size:16px;margin-bottom:16px">${rating}</div>
      <div class="stat-row"><span>Strikes</span><span class="stat-value">${stats.strikes}</span></div>
      <div class="stat-row"><span>Spares</span><span class="stat-value">${stats.spares}</span></div>
      <div class="stat-row"><span>Gutters</span><span class="stat-value">${stats.gutters}</span></div>
      <div class="stat-row"><span>Total Pins</span><span class="stat-value">${stats.totalPins}</span></div>
      <div class="stat-row"><span>Best Streak</span><span class="stat-value">${stats.maxStreak}</span></div>
      <button class="ui-btn primary" onclick="window.__ui.playAgain()">▶ PLAY AGAIN</button>
      <button class="ui-btn" onclick="window.__ui.backToTitle()">← MAIN MENU</button>
    `;

    (window as any).__ui.playAgain = () => this.onPlayAgain();
    (window as any).__ui.backToTitle = () => this.showTitleScreen();

    this.showPanel('ui-game-over');
  }

  showPause() {
    const panel = document.getElementById('ui-pause')!;
    panel.innerHTML = `
      <div class="ui-section-title">PAUSED</div>
      <button class="ui-btn primary" onclick="window.__ui.resume()">▶ RESUME</button>
      <button class="ui-btn" onclick="window.__ui.quit()">✕ QUIT TO MENU</button>
    `;

    (window as any).__ui.resume = () => this.onResume();
    (window as any).__ui.quit = () => this.onQuit();

    this.showPanel('ui-pause');
  }

  showLeaderboard(scores: { score: number; date: string }[]) {
    const panel = document.getElementById('ui-leaderboard')!;
    let rows = '';
    scores.slice(0, 10).forEach((entry, i) => {
      const medal = i === 0 ? 'leaderboard-gold' : i === 1 ? 'leaderboard-silver' : i === 2 ? 'leaderboard-bronze' : '';
      rows += `<tr class="${medal}"><td>${i + 1}</td><td>${entry.score}</td><td>${entry.date}</td></tr>`;
    });

    if (scores.length === 0) {
      rows = '<tr><td colspan="3" style="color:rgba(255,255,255,0.4)">No games yet</td></tr>';
    }

    panel.innerHTML = `
      <div class="ui-section-title">🏆 LEADERBOARD</div>
      <table class="leaderboard-table">
        <tr><th>#</th><th>Score</th><th>Date</th></tr>
        ${rows}
      </table>
      <button class="ui-btn" onclick="window.__ui.backToTitle()">← BACK</button>
    `;
    (window as any).__ui.backToTitle = () => this.showTitleScreen();
    this.showPanel('ui-leaderboard');
  }

  showAchievements(achievements: { id: string; name: string; description: string; unlocked: boolean }[]) {
    const panel = document.getElementById('ui-achievements')!;
    let cardsHtml = '';
    for (const ach of achievements) {
      const cls = ach.unlocked ? ' unlocked' : '';
      const icon = ach.unlocked ? '✓' : '🔒';
      cardsHtml += `
        <div class="achievement-card${cls}">
          <div class="achievement-name">${icon} ${ach.name}</div>
          <div class="achievement-desc">${ach.description}</div>
        </div>
      `;
    }

    panel.innerHTML = `
      <div class="ui-section-title">⭐ ACHIEVEMENTS</div>
      <div class="achievement-grid">${cardsHtml}</div>
      <button class="ui-btn" onclick="window.__ui.backToTitle()">← BACK</button>
    `;
    (window as any).__ui.backToTitle = () => this.showTitleScreen();
    this.showPanel('ui-achievements');
  }

  showChallenges(bestScores: Record<string, number> = {}) {
    const panel = document.getElementById('ui-challenges')!;
    let cardsHtml = '';
    for (const [key, challenge] of Object.entries(CHALLENGES)) {
      const best = bestScores[key];
      const bestStr = best !== undefined ? `Best: ${best}/${challenge.frames}` : 'Not attempted';
      cardsHtml += `
        <div class="ball-card" onclick="window.__startChallenge('${key}')">
          <div class="ball-name">${challenge.name}</div>
          <div class="ball-desc">${challenge.description}</div>
          <div class="ball-desc" style="color:rgba(0,255,255,0.5);margin-top:4px">${bestStr}</div>
        </div>
      `;
    }

    panel.innerHTML = `
      <div class="ui-section-title">🏅 CHALLENGES</div>
      <div class="ball-grid">${cardsHtml}</div>
      <button class="ui-btn" onclick="window.__ui.backToTitle()">← BACK</button>
    `;

    (window as any).__startChallenge = (type: string) => {
      this.onStartChallenge(type as ChallengeType);
    };
    (window as any).__ui.backToTitle = () => this.showTitleScreen();
    this.showPanel('ui-challenges');
  }

  showChallengeResult(success: boolean, challengeName: string, stats: { successes: number; total: number; time: number }) {
    const panel = document.getElementById('ui-challenge-result')!;
    const emoji = success ? '🏆' : '💪';
    const msg = success ? 'CHALLENGE COMPLETE!' : 'KEEP TRYING!';
    const timeStr = stats.time > 0 ? `<div class="stat-row"><span>Time</span><span class="stat-value">${Math.floor(stats.time)}s</span></div>` : '';

    panel.innerHTML = `
      <div class="ui-section-title">${emoji} ${msg}</div>
      <div style="font-size:20px;color:#ffffff;margin-bottom:16px">${challengeName}</div>
      <div class="stat-row"><span>Successes</span><span class="stat-value">${stats.successes} / ${stats.total}</span></div>
      ${timeStr}
      <button class="ui-btn primary" onclick="window.__ui.backToTitle()">← MAIN MENU</button>
    `;

    (window as any).__ui.backToTitle = () => this.showTitleScreen();
    this.showPanel('ui-challenge-result');
  }
}

/**
 * Astro Bowl VR — Visual Effects
 * Strike/spare celebrations, particle explosions, text popups,
 * camera shake, slow-motion, ball trail effects.
 */
import {
  Group, Mesh, SphereGeometry, BoxGeometry,
  MeshBasicMaterial, Color, Vector3, AdditiveBlending,
} from '@iwsdk/core';

interface Particle {
  mesh: Mesh;
  velocity: Vector3;
  life: number;
  maxLife: number;
}

export class EffectsManager {
  group: Group;
  private particles: Particle[] = [];
  private cameraShakeIntensity: number = 0;
  private cameraShakeDecay: number = 0.92;
  private slowMotionActive: boolean = false;
  private slowMotionTimer: number = 0;
  private slowMotionDuration: number = 0;
  timeScale: number = 1;

  constructor() {
    this.group = new Group();
  }

  /**
   * Spawn a burst of particles at a position.
   */
  spawnParticleBurst(
    position: Vector3,
    count: number,
    color: Color,
    speed: number = 5,
    lifetime: number = 1.5,
  ) {
    for (let i = 0; i < count; i++) {
      const size = 0.02 + Math.random() * 0.05;
      const geo = Math.random() > 0.5
        ? new SphereGeometry(size, 6, 6)
        : new BoxGeometry(size, size, size);
      const mat = new MeshBasicMaterial({
        color,
        transparent: true,
        opacity: 0.8,
        blending: AdditiveBlending,
      });
      const mesh = new Mesh(geo, mat);
      mesh.position.copy(position);

      const velocity = new Vector3(
        (Math.random() - 0.5) * speed,
        Math.random() * speed * 0.8 + 1,
        (Math.random() - 0.5) * speed,
      );

      const particle: Particle = {
        mesh,
        velocity,
        life: lifetime + Math.random() * 0.5,
        maxLife: lifetime + Math.random() * 0.5,
      };

      this.particles.push(particle);
      this.group.add(mesh);
    }
  }

  /**
   * Strike celebration — big particle explosion + camera shake.
   */
  playStrikeCelebration(pinPosition: Vector3) {
    const colors = [
      new Color(0xff4444),
      new Color(0x00ffff),
      new Color(0xffff00),
      new Color(0xff00ff),
    ];

    // Big central burst
    for (const color of colors) {
      this.spawnParticleBurst(pinPosition, 15, color, 8, 2);
    }

    // Ring of particles
    for (let angle = 0; angle < Math.PI * 2; angle += Math.PI / 8) {
      const pos = pinPosition.clone().add(new Vector3(
        Math.cos(angle) * 0.5,
        0.5,
        Math.sin(angle) * 0.5,
      ));
      this.spawnParticleBurst(pos, 3, new Color(0x00ffff), 4, 1.5);
    }

    this.triggerCameraShake(0.15);
  }

  /**
   * Spare celebration — more subtle particles.
   */
  playSpareCelebration(pinPosition: Vector3) {
    this.spawnParticleBurst(pinPosition, 20, new Color(0xffaa00), 5, 1.5);
    this.spawnParticleBurst(pinPosition, 10, new Color(0x00ffff), 3, 1.2);
    this.triggerCameraShake(0.06);
  }

  /**
   * Gutter visual.
   */
  playGutterEffect(ballPosition: Vector3) {
    this.spawnParticleBurst(ballPosition, 8, new Color(0x666666), 2, 0.8);
  }

  /**
   * Turkey celebration (3 strikes).
   */
  playTurkeyCelebration(position: Vector3) {
    this.playStrikeCelebration(position);
    // Extra gold particles
    setTimeout(() => {
      this.spawnParticleBurst(position, 30, new Color(0xffd700), 10, 2.5);
      this.triggerCameraShake(0.25);
    }, 200);
  }

  /**
   * Pin hit impact.
   */
  playPinHitEffect(position: Vector3, intensity: number) {
    const count = Math.ceil(intensity * 5);
    this.spawnParticleBurst(position, count, new Color(0xffffff), intensity * 3, 0.6);
  }

  /**
   * Achievement unlock effect.
   */
  playAchievementEffect() {
    const center = new Vector3(0, 2, -3);
    this.spawnParticleBurst(center, 30, new Color(0xffd700), 6, 2);
    this.spawnParticleBurst(center, 20, new Color(0xffaa00), 4, 1.5);
  }

  /**
   * Camera shake.
   */
  triggerCameraShake(intensity: number) {
    this.cameraShakeIntensity = Math.max(this.cameraShakeIntensity, intensity);
  }

  getCameraShakeOffset(): Vector3 {
    if (this.cameraShakeIntensity < 0.001) return new Vector3();
    return new Vector3(
      (Math.random() - 0.5) * this.cameraShakeIntensity,
      (Math.random() - 0.5) * this.cameraShakeIntensity * 0.5,
      (Math.random() - 0.5) * this.cameraShakeIntensity * 0.3,
    );
  }

  /**
   * Start slow motion.
   */
  startSlowMotion(duration: number, scale: number = 0.3) {
    this.slowMotionActive = true;
    this.slowMotionTimer = 0;
    this.slowMotionDuration = duration;
    this.timeScale = scale;
  }

  /**
   * Update effects.
   */
  update(dt: number) {
    // Update particles
    for (let i = this.particles.length - 1; i >= 0; i--) {
      const p = this.particles[i];
      p.life -= dt;

      if (p.life <= 0) {
        this.group.remove(p.mesh);
        p.mesh.geometry.dispose();
        (p.mesh.material as MeshBasicMaterial).dispose();
        this.particles.splice(i, 1);
        continue;
      }

      // Gravity
      p.velocity.y -= 9.81 * dt * 0.3;

      // Update position
      p.mesh.position.x += p.velocity.x * dt;
      p.mesh.position.y += p.velocity.y * dt;
      p.mesh.position.z += p.velocity.z * dt;

      // Fade out
      const lifeRatio = p.life / p.maxLife;
      (p.mesh.material as MeshBasicMaterial).opacity = lifeRatio * 0.8;

      // Scale down
      const scale = 0.3 + lifeRatio * 0.7;
      p.mesh.scale.setScalar(scale);

      // Floor bounce
      if (p.mesh.position.y < 0) {
        p.mesh.position.y = 0;
        p.velocity.y *= -0.3;
        p.velocity.x *= 0.8;
        p.velocity.z *= 0.8;
      }
    }

    // Camera shake decay
    this.cameraShakeIntensity *= this.cameraShakeDecay;
    if (this.cameraShakeIntensity < 0.001) this.cameraShakeIntensity = 0;

    // Slow motion
    if (this.slowMotionActive) {
      this.slowMotionTimer += dt;
      if (this.slowMotionTimer >= this.slowMotionDuration) {
        this.slowMotionActive = false;
        this.timeScale = 1;
      } else {
        // Ease back to normal near end
        const progress = this.slowMotionTimer / this.slowMotionDuration;
        if (progress > 0.7) {
          this.timeScale = 0.3 + (progress - 0.7) / 0.3 * 0.7;
        }
      }
    }
  }

  cleanup() {
    for (const p of this.particles) {
      this.group.remove(p.mesh);
      p.mesh.geometry.dispose();
      (p.mesh.material as MeshBasicMaterial).dispose();
    }
    this.particles = [];
  }
}

/**
 * Astro Bowl VR — Procedural Audio System
 * Ball rolling, pin crashes, gutter thud, strike fanfare, spare chime,
 * ambient music — all via Web Audio API.
 */
export class AudioManager {
  private ctx: AudioContext;
  private masterGain: GainNode;
  private musicGain: GainNode;
  private sfxGain: GainNode;
  private musicVolume: number = 0.3;
  private sfxVolume: number = 0.6;
  private ambientOsc: OscillatorNode[] = [];
  private ambientGains: GainNode[] = [];
  private rollingNoise: AudioBufferSourceNode | null = null;
  private rollingGain: GainNode;
  private rollingFilter: BiquadFilterNode;
  private initialized: boolean = false;

  constructor() {
    this.ctx = new AudioContext();
    this.masterGain = this.ctx.createGain();
    this.masterGain.gain.value = 0.8;
    this.masterGain.connect(this.ctx.destination);

    this.musicGain = this.ctx.createGain();
    this.musicGain.gain.value = this.musicVolume;
    this.musicGain.connect(this.masterGain);

    this.sfxGain = this.ctx.createGain();
    this.sfxGain.gain.value = this.sfxVolume;
    this.sfxGain.connect(this.masterGain);

    this.rollingGain = this.ctx.createGain();
    this.rollingGain.gain.value = 0;
    this.rollingGain.connect(this.sfxGain);

    this.rollingFilter = this.ctx.createBiquadFilter();
    this.rollingFilter.type = 'lowpass';
    this.rollingFilter.frequency.value = 200;
    this.rollingFilter.connect(this.rollingGain);
  }

  async init() {
    if (this.initialized) return;
    if (this.ctx.state === 'suspended') {
      await this.ctx.resume();
    }
    this.initialized = true;
  }

  /**
   * Start ambient background music — synth pads.
   */
  startAmbientMusic() {
    if (this.ambientOsc.length > 0) return;

    // Deep bass drone
    const bassOsc = this.ctx.createOscillator();
    bassOsc.type = 'sine';
    bassOsc.frequency.value = 55; // A1
    const bassGain = this.ctx.createGain();
    bassGain.gain.value = 0.1;
    bassOsc.connect(bassGain);
    bassGain.connect(this.musicGain);
    bassOsc.start();
    this.ambientOsc.push(bassOsc);
    this.ambientGains.push(bassGain);

    // Mid pad (filtered sawtooth)
    const padOsc = this.ctx.createOscillator();
    padOsc.type = 'sawtooth';
    padOsc.frequency.value = 110;
    const padFilter = this.ctx.createBiquadFilter();
    padFilter.type = 'lowpass';
    padFilter.frequency.value = 300;
    padFilter.Q.value = 2;
    const padGain = this.ctx.createGain();
    padGain.gain.value = 0.05;
    padOsc.connect(padFilter);
    padFilter.connect(padGain);
    padGain.connect(this.musicGain);
    padOsc.start();
    this.ambientOsc.push(padOsc);
    this.ambientGains.push(padGain);

    // High shimmer (triangle with LFO)
    const shimmerOsc = this.ctx.createOscillator();
    shimmerOsc.type = 'triangle';
    shimmerOsc.frequency.value = 440;
    const lfo = this.ctx.createOscillator();
    lfo.type = 'sine';
    lfo.frequency.value = 0.2;
    const lfoGain = this.ctx.createGain();
    lfoGain.gain.value = 20;
    lfo.connect(lfoGain);
    lfoGain.connect(shimmerOsc.frequency);
    lfo.start();
    const shimmerGain = this.ctx.createGain();
    shimmerGain.gain.value = 0.02;
    shimmerOsc.connect(shimmerGain);
    shimmerGain.connect(this.musicGain);
    shimmerOsc.start();
    this.ambientOsc.push(shimmerOsc);
    this.ambientGains.push(shimmerGain);

    // Subtle sub-bass pulse
    const subOsc = this.ctx.createOscillator();
    subOsc.type = 'sine';
    subOsc.frequency.value = 36.7; // D1
    const subLfo = this.ctx.createOscillator();
    subLfo.type = 'sine';
    subLfo.frequency.value = 0.08;
    const subLfoGain = this.ctx.createGain();
    subLfoGain.gain.value = 0.04;
    subLfo.connect(subLfoGain);
    const subGain = this.ctx.createGain();
    subGain.gain.value = 0.06;
    subLfoGain.connect(subGain.gain);
    subOsc.connect(subGain);
    subGain.connect(this.musicGain);
    subOsc.start();
    subLfo.start();
    this.ambientOsc.push(subOsc);
    this.ambientGains.push(subGain);
  }

  stopAmbientMusic() {
    for (const osc of this.ambientOsc) {
      try { osc.stop(); } catch {}
    }
    this.ambientOsc = [];
    this.ambientGains = [];
  }

  /**
   * Ball rolling sound — continuous noise, pitch/volume scales with speed.
   */
  startRollingSound() {
    if (this.rollingNoise) return;

    // Create brown noise buffer
    const bufferSize = this.ctx.sampleRate * 2;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    let last = 0;
    for (let i = 0; i < bufferSize; i++) {
      const white = Math.random() * 2 - 1;
      data[i] = (last + 0.02 * white) / 1.02;
      last = data[i];
      data[i] *= 3.5;
    }

    this.rollingNoise = this.ctx.createBufferSource();
    this.rollingNoise.buffer = buffer;
    this.rollingNoise.loop = true;
    this.rollingNoise.connect(this.rollingFilter);
    this.rollingNoise.start();
    this.rollingGain.gain.value = 0;
  }

  updateRollingSound(speed: number) {
    if (!this.rollingNoise) return;
    const vol = Math.min(0.4, speed * 0.06);
    const freq = 150 + speed * 80;
    this.rollingGain.gain.setTargetAtTime(vol, this.ctx.currentTime, 0.05);
    this.rollingFilter.frequency.setTargetAtTime(freq, this.ctx.currentTime, 0.05);
  }

  stopRollingSound() {
    if (this.rollingNoise) {
      this.rollingGain.gain.setTargetAtTime(0, this.ctx.currentTime, 0.05);
      try {
        this.rollingNoise.stop(this.ctx.currentTime + 0.1);
      } catch {}
      this.rollingNoise = null;
    }
  }

  /**
   * Pin crash sound — filtered noise burst with randomized pitch.
   */
  playPinCrash(intensity: number = 1) {
    const bufferSize = this.ctx.sampleRate * 0.3;
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      const t = i / bufferSize;
      data[i] = (Math.random() * 2 - 1) * Math.exp(-t * 8) * intensity;
    }

    const source = this.ctx.createBufferSource();
    source.buffer = buffer;

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.value = 800 + Math.random() * 600;
    filter.Q.value = 1.5;

    const gain = this.ctx.createGain();
    gain.gain.value = 0.3 * intensity;
    gain.gain.setTargetAtTime(0, this.ctx.currentTime + 0.1, 0.1);

    source.connect(filter);
    filter.connect(gain);
    gain.connect(this.sfxGain);
    source.start();
    source.stop(this.ctx.currentTime + 0.4);
  }

  /**
   * Multiple pin crash (scatter) — rapid succession.
   */
  playPinScatter(count: number) {
    for (let i = 0; i < Math.min(count, 5); i++) {
      setTimeout(() => {
        this.playPinCrash(0.5 + Math.random() * 0.5);
      }, i * 50 + Math.random() * 30);
    }
  }

  /**
   * Gutter thud — low impact sound.
   */
  playGutterThud() {
    const osc = this.ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.value = 60;
    osc.frequency.setTargetAtTime(30, this.ctx.currentTime + 0.05, 0.1);

    const gain = this.ctx.createGain();
    gain.gain.value = 0.4;
    gain.gain.setTargetAtTime(0, this.ctx.currentTime + 0.1, 0.15);

    osc.connect(gain);
    gain.connect(this.sfxGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 0.5);

    // Add noise component
    const bufSize = this.ctx.sampleRate * 0.15;
    const buf = this.ctx.createBuffer(1, bufSize, this.ctx.sampleRate);
    const d = buf.getChannelData(0);
    for (let i = 0; i < bufSize; i++) {
      d[i] = (Math.random() * 2 - 1) * Math.exp(-i / bufSize * 5) * 0.2;
    }
    const noise = this.ctx.createBufferSource();
    noise.buffer = buf;
    const nGain = this.ctx.createGain();
    nGain.gain.value = 0.3;
    noise.connect(nGain);
    nGain.connect(this.sfxGain);
    noise.start();
  }

  /**
   * Strike fanfare — ascending arpeggio + crash cymbal.
   */
  playStrikeFanfare() {
    const notes = [261.6, 329.6, 392, 523.2, 659.2, 784]; // C4 to G5
    notes.forEach((freq, i) => {
      setTimeout(() => {
        const osc = this.ctx.createOscillator();
        osc.type = i < 3 ? 'triangle' : 'sine';
        osc.frequency.value = freq;

        const gain = this.ctx.createGain();
        gain.gain.value = 0.15;
        gain.gain.setTargetAtTime(0, this.ctx.currentTime + 0.3, 0.2);

        osc.connect(gain);
        gain.connect(this.sfxGain);
        osc.start();
        osc.stop(this.ctx.currentTime + 0.6);
      }, i * 80);
    });

    // Crash cymbal (noise burst)
    setTimeout(() => {
      const bufSize = this.ctx.sampleRate * 0.8;
      const buf = this.ctx.createBuffer(1, bufSize, this.ctx.sampleRate);
      const d = buf.getChannelData(0);
      for (let i = 0; i < bufSize; i++) {
        d[i] = (Math.random() * 2 - 1) * Math.exp(-i / bufSize * 4) * 0.15;
      }
      const noise = this.ctx.createBufferSource();
      noise.buffer = buf;
      const filter = this.ctx.createBiquadFilter();
      filter.type = 'highpass';
      filter.frequency.value = 3000;
      const gain = this.ctx.createGain();
      gain.gain.value = 0.2;
      noise.connect(filter);
      filter.connect(gain);
      gain.connect(this.sfxGain);
      noise.start();
    }, 400);
  }

  /**
   * Spare chime — pleasant ascending tones.
   */
  playSpareChime() {
    const notes = [392, 493.9, 587.3]; // G4, B4, D5
    notes.forEach((freq, i) => {
      setTimeout(() => {
        const osc = this.ctx.createOscillator();
        osc.type = 'sine';
        osc.frequency.value = freq;

        const gain = this.ctx.createGain();
        gain.gain.value = 0.12;
        gain.gain.setTargetAtTime(0, this.ctx.currentTime + 0.4, 0.2);

        osc.connect(gain);
        gain.connect(this.sfxGain);
        osc.start();
        osc.stop(this.ctx.currentTime + 0.8);
      }, i * 120);
    });
  }

  /**
   * Gutter ball sad trombone.
   */
  playGutterSad() {
    const notes = [293.7, 277.2, 261.6, 246.9]; // D4 descending
    notes.forEach((freq, i) => {
      setTimeout(() => {
        const osc = this.ctx.createOscillator();
        osc.type = 'triangle';
        osc.frequency.value = freq;

        const gain = this.ctx.createGain();
        gain.gain.value = 0.1;
        gain.gain.setTargetAtTime(0, this.ctx.currentTime + 0.3, 0.15);

        osc.connect(gain);
        gain.connect(this.sfxGain);
        osc.start();
        osc.stop(this.ctx.currentTime + 0.5);
      }, i * 200);
    });
  }

  /**
   * UI select click.
   */
  playUIClick() {
    const osc = this.ctx.createOscillator();
    osc.type = 'sine';
    osc.frequency.value = 1200;

    const gain = this.ctx.createGain();
    gain.gain.value = 0.08;
    gain.gain.setTargetAtTime(0, this.ctx.currentTime + 0.03, 0.02);

    osc.connect(gain);
    gain.connect(this.sfxGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 0.1);
  }

  /**
   * Throw whoosh sound.
   */
  playThrowWhoosh(speed: number) {
    const bufSize = this.ctx.sampleRate * 0.3;
    const buf = this.ctx.createBuffer(1, bufSize, this.ctx.sampleRate);
    const d = buf.getChannelData(0);
    for (let i = 0; i < bufSize; i++) {
      const t = i / bufSize;
      d[i] = (Math.random() * 2 - 1) * Math.sin(t * Math.PI) * 0.3;
    }

    const source = this.ctx.createBufferSource();
    source.buffer = buf;
    source.playbackRate.value = 0.8 + speed * 0.1;

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'bandpass';
    filter.frequency.value = 600 + speed * 200;
    filter.Q.value = 1;

    const gain = this.ctx.createGain();
    gain.gain.value = 0.2;

    source.connect(filter);
    filter.connect(gain);
    gain.connect(this.sfxGain);
    source.start();
  }

  /**
   * Achievement unlock sound.
   */
  playAchievementUnlock() {
    const notes = [523.2, 659.2, 784, 1046.5]; // C5, E5, G5, C6
    notes.forEach((freq, i) => {
      setTimeout(() => {
        const osc = this.ctx.createOscillator();
        osc.type = 'sine';
        osc.frequency.value = freq;

        const gain = this.ctx.createGain();
        gain.gain.value = 0.1;
        gain.gain.setTargetAtTime(0, this.ctx.currentTime + 0.25, 0.15);

        osc.connect(gain);
        gain.connect(this.sfxGain);
        osc.start();
        osc.stop(this.ctx.currentTime + 0.5);
      }, i * 100);
    });
  }

  /**
   * Ball return mechanical sound.
   */
  playBallReturn() {
    const osc = this.ctx.createOscillator();
    osc.type = 'sawtooth';
    osc.frequency.value = 80;
    osc.frequency.linearRampToValueAtTime(120, this.ctx.currentTime + 0.4);

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 300;

    const gain = this.ctx.createGain();
    gain.gain.value = 0.1;
    gain.gain.setTargetAtTime(0, this.ctx.currentTime + 0.3, 0.15);

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.sfxGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 0.6);
  }

  /**
   * Pin reset / sweep sound.
   */
  playSweepSound() {
    const osc = this.ctx.createOscillator();
    osc.type = 'sawtooth';
    osc.frequency.value = 150;
    osc.frequency.linearRampToValueAtTime(80, this.ctx.currentTime + 0.5);

    const filter = this.ctx.createBiquadFilter();
    filter.type = 'lowpass';
    filter.frequency.value = 400;

    const gain = this.ctx.createGain();
    gain.gain.value = 0.12;
    gain.gain.setTargetAtTime(0, this.ctx.currentTime + 0.4, 0.2);

    osc.connect(filter);
    filter.connect(gain);
    gain.connect(this.sfxGain);
    osc.start();
    osc.stop(this.ctx.currentTime + 0.7);
  }

  /**
   * Turkey (3 strikes) celebration.
   */
  playTurkeyCelebration() {
    this.playStrikeFanfare();
    setTimeout(() => {
      const notes = [784, 880, 987.8, 1046.5, 1174.7, 1318.5]; // G5 to E6
      notes.forEach((freq, i) => {
        setTimeout(() => {
          const osc = this.ctx.createOscillator();
          osc.type = 'sine';
          osc.frequency.value = freq;
          const gain = this.ctx.createGain();
          gain.gain.value = 0.08;
          gain.gain.setTargetAtTime(0, this.ctx.currentTime + 0.2, 0.1);
          osc.connect(gain);
          gain.connect(this.sfxGain);
          osc.start();
          osc.stop(this.ctx.currentTime + 0.4);
        }, i * 60);
      });
    }, 600);
  }

  setMusicVolume(vol: number) {
    this.musicVolume = vol;
    this.musicGain.gain.setTargetAtTime(vol, this.ctx.currentTime, 0.05);
  }

  setSFXVolume(vol: number) {
    this.sfxVolume = vol;
    this.sfxGain.gain.setTargetAtTime(vol, this.ctx.currentTime, 0.05);
  }
}

