export class ChallengeManager {
  currentChallenge: ChallengeConfig | null = null;
  frameIndex: number = 0;
  successes: number = 0;
  elapsedTime: number = 0;
  isActive: boolean = false;
  private storageKey = 'astro-bowl-challenges';
  bestScores: Record<string, number> = {};

  onChallengeComplete: (success: boolean, stats: { successes: number; total: number; time: number }) => void = () => {};

  constructor() {
    this.loadBests();
  }

  private loadBests() {
    try {
      const saved = localStorage.getItem(this.storageKey);
      if (saved) this.bestScores = JSON.parse(saved);
    } catch {}
  }

  private saveBests() {
    try {
      localStorage.setItem(this.storageKey, JSON.stringify(this.bestScores));
    } catch {}
  }

  startChallenge(type: ChallengeType) {
    this.currentChallenge = CHALLENGES[type];
    this.frameIndex = 0;
    this.successes = 0;
    this.elapsedTime = 0;
    this.isActive = true;
  }

  /**
   * Get the pin setup for the current frame in spare/split challenges.
   */
  getCurrentPinSetup(): boolean[] | null {
    if (!this.currentChallenge) return null;

    if (this.currentChallenge.type === ChallengeType.SPARE_PRACTICE) {
      const setup = SPARE_SETUPS[this.frameIndex % SPARE_SETUPS.length];
      return setup.pins;
    }

    if (this.currentChallenge.type === ChallengeType.SPLIT_CHALLENGE) {
      const setup = SPLIT_SETUPS[this.frameIndex % SPLIT_SETUPS.length];
      return setup.pins;
    }

    return null; // Normal full pins
  }

  getCurrentSetupName(): string {
    if (!this.currentChallenge) return '';

    if (this.currentChallenge.type === ChallengeType.SPARE_PRACTICE) {
      return SPARE_SETUPS[this.frameIndex % SPARE_SETUPS.length].name;
    }

    if (this.currentChallenge.type === ChallengeType.SPLIT_CHALLENGE) {
      return SPLIT_SETUPS[this.frameIndex % SPLIT_SETUPS.length].name;
    }

    return '';
  }

  /**
   * Record a frame result for the challenge.
   * Returns true if the player succeeded this frame.
   */
  recordFrameResult(isStrike: boolean, isSpare: boolean, allPinsDown: boolean): boolean {
    if (!this.currentChallenge || !this.isActive) return false;

    let success = false;

    switch (this.currentChallenge.type) {
      case ChallengeType.STRIKE_CHALLENGE:
        success = isStrike;
        break;
      case ChallengeType.SPARE_PRACTICE:
        success = allPinsDown; // Cleared all remaining pins
        break;
      case ChallengeType.SPLIT_CHALLENGE:
        success = allPinsDown;
        break;
      case ChallengeType.SPEED_BOWL:
        success = true; // Just completing frames counts
        break;
    }

    if (success) this.successes++;
    this.frameIndex++;

    // Check completion
    if (this.frameIndex >= this.currentChallenge.frames) {
      this.isActive = false;
      const passed = this.successes >= this.currentChallenge.targetScore ||
        (this.currentChallenge.type === ChallengeType.SPEED_BOWL &&
         this.elapsedTime < this.currentChallenge.timeLimit);

      // Save best
      const key = this.currentChallenge.type;
      if (!this.bestScores[key] || this.successes > this.bestScores[key]) {
        this.bestScores[key] = this.successes;
        this.saveBests();
      }

      this.onChallengeComplete(passed, {
        successes: this.successes,
        total: this.currentChallenge.frames,
        time: this.elapsedTime,
      });
    }

    return success;
  }

  updateTime(dt: number) {
    if (this.isActive && this.currentChallenge?.timeLimit) {
      this.elapsedTime += dt;
    }
  }

  getRemainingTime(): number {
    if (!this.currentChallenge?.timeLimit) return -1;
    return Math.max(0, this.currentChallenge.timeLimit - this.elapsedTime);
  }
}

/**
 * Astro Bowl VR — Browser Input Handler
 * Mouse click-drag aim, hold to charge power, release to throw.
 * WASD movement, keyboard shortcuts.
 */
import { World, Vector3 } from '@iwsdk/core';

export class BrowserInputHandler {
  private world: World;
  private canvas: HTMLCanvasElement;
  private isDragging: boolean = false;
  private dragStart: { x: number; y: number } = { x: 0, y: 0 };
  private dragCurrent: { x: number; y: number } = { x: 0, y: 0 };
  private powerCharging: boolean = false;
  private power: number = 0;
  private powerDir: number = 1;
  private aimX: number = 0; // -1 to 1, lateral aim

  // Callbacks
  onThrow: (velocity: Vector3) => void = () => {};
  onPowerChange: (power: number) => void = () => {};
  onAimChange: (aimX: number) => void = () => {};
  onConfirm: () => void = () => {};
  onBack: () => void = () => {};
  onPause: () => void = () => {};
  onMenuUp: () => void = () => {};
  onMenuDown: () => void = () => {};
  onStartCharge: () => void = () => {};

  private enabled: boolean = true;

  constructor(world: World, canvas: HTMLCanvasElement) {
    this.world = world;
    this.canvas = canvas;
    this.setupListeners();
  }

  private setupListeners() {
    this.canvas.addEventListener('mousedown', (e) => {
      if (!this.enabled) return;
      this.isDragging = true;
      this.dragStart = { x: e.clientX, y: e.clientY };
      this.dragCurrent = { ...this.dragStart };
      this.powerCharging = true;
      this.power = 0;
      this.onStartCharge();
    });

    this.canvas.addEventListener('mousemove', (e) => {
      if (!this.isDragging) return;
      this.dragCurrent = { x: e.clientX, y: e.clientY };

      // Calculate aim direction from drag
      const dx = (this.dragCurrent.x - this.dragStart.x) / window.innerWidth;
      this.aimX = Math.max(-1, Math.min(1, dx * 3));
      this.onAimChange(this.aimX);
    });

    this.canvas.addEventListener('mouseup', () => {
      if (!this.isDragging) return;
      this.isDragging = false;
      this.powerCharging = false;

      // Calculate throw velocity from power and aim
      const speed = 3 + this.power * 9; // 3-12 m/s
      const velocity = new Vector3(
        this.aimX * 2,   // lateral direction
        0,
        -speed,           // forward (negative Z)
      );
      this.onThrow(velocity);
      this.power = 0;
      this.aimX = 0;
    });

    // Keyboard
    document.addEventListener('keydown', (e) => {
      if (!this.enabled) return;

      switch (e.key) {
        case 'Enter':
        case ' ':
          e.preventDefault();
          this.onConfirm();
          break;
        case 'Escape':
          this.onPause();
          break;
        case 'Backspace':
          this.onBack();
          break;
        case 'ArrowUp':
        case 'w':
          this.onMenuUp();
          break;
        case 'ArrowDown':
        case 's':
          this.onMenuDown();
          break;
      }
    });
  }

  setEnabled(enabled: boolean) {
    this.enabled = enabled;
  }

  update(dt: number) {
    // Power charging oscillates while mouse is held
    if (this.powerCharging) {
      this.power += this.powerDir * dt * 1.5;
      if (this.power >= 1) {
        this.power = 1;
        this.powerDir = -1;
      } else if (this.power <= 0) {
        this.power = 0;
        this.powerDir = 1;
      }
      this.onPowerChange(this.power);
    }
  }

  getPower(): number {
    return this.power;
  }

  getAimX(): number {
    return this.aimX;
  }

  isDragActive(): boolean {
    return this.isDragging;
  }
}

/**
 * Astro Bowl VR — Aim Indicator
 * Projected trajectory line showing ball direction in browser mode.
 */
import {
  Group, LineSegments, BufferGeometry, Float32BufferAttribute,
  LineBasicMaterial, Color, AdditiveBlending, Mesh, ConeGeometry,
  MeshBasicMaterial, Vector3,
} from '@iwsdk/core';
import { LANE } from './lane';

export class AimIndicator {
  group: Group;
  private line: LineSegments;
  private arrow: Mesh;
  private visible: boolean = false;
  private aimX: number = 0;
  private power: number = 0;

  constructor(color: Color) {
    this.group = new Group();

    // Trajectory line
    const lineGeo = new BufferGeometry();
    const positions = new Float32Array(60); // 20 segments * 3
    lineGeo.setAttribute('position', new Float32BufferAttribute(positions, 3));
    const lineMat = new LineBasicMaterial({
      color,
      transparent: true,
      opacity: 0.5,
      blending: AdditiveBlending,
    });
    this.line = new LineSegments(lineGeo, lineMat);
    this.line.frustumCulled = false;
    this.group.add(this.line);

    // Arrow tip
    const arrowMat = new MeshBasicMaterial({
      color,
      transparent: true,
      opacity: 0.6,
      blending: AdditiveBlending,
    });
    this.arrow = new Mesh(new ConeGeometry(0.06, 0.2, 8), arrowMat);
    this.arrow.rotation.x = Math.PI / 2; // Point forward (-Z)
    this.group.add(this.arrow);

    this.hide();
  }

  show() {
    this.visible = true;
    this.group.visible = true;
  }

  hide() {
    this.visible = false;
    this.group.visible = false;
  }

  /**
   * Update aim based on lateral offset and power.
   */
  update(aimX: number, power: number) {
    if (!this.visible) return;

    this.aimX = aimX;
    this.power = power;

    const startZ = LANE.FOUL_LINE_Z - 0.1;
    const speed = 3 + power * 9;
    const endZ = startZ - Math.min(speed * 2.5, Math.abs(LANE.HEADPIN_Z - startZ));

    const segments = 20;
    const positions: number[] = [];
    const y = LANE.SURFACE_Y + 0.05;

    for (let i = 0; i < segments - 1; i++) {
      const t1 = i / (segments - 1);
      const t2 = (i + 1) / (segments - 1);

      const z1 = startZ + (endZ - startZ) * t1;
      const z2 = startZ + (endZ - startZ) * t2;
      const x1 = aimX * 2 * t1; // Lateral drift
      const x2 = aimX * 2 * t2;

      positions.push(x1, y, z1, x2, y, z2);
    }

    const geo = this.line.geometry;
    const posAttr = geo.getAttribute('position');
    const arr = posAttr.array as Float32Array;
    arr.fill(0);
    for (let i = 0; i < Math.min(positions.length, arr.length); i++) {
      arr[i] = positions[i];
    }
    posAttr.needsUpdate = true;
    geo.setDrawRange(0, Math.min(positions.length / 3, 40));

    // Update opacity based on power
    (this.line.material as LineBasicMaterial).opacity = 0.3 + power * 0.4;
    (this.arrow.material as MeshBasicMaterial).opacity = 0.4 + power * 0.4;

    // Position arrow at end of line
    const lastX = aimX * 2;
    this.arrow.position.set(lastX, y + 0.02, endZ);
  }
}

